#[derive(Debug, Clone)]
pub struct RuntimeLlmProviderStatus {
    status: LlmProviderStatus,
    strict: bool,
    will_fallback_to_fake: bool,
    config_source: RuntimeConfigSource,
    active_profile: Option<String>,
    task_run_network_allowed: bool,
    budget: LlmRequestBudget,
    sensitive_guard_mode: PromptSensitiveGuardMode,
    sensitive_guard_invalid: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RuntimeConfigSource {
    Env,
    WorkspaceConfig,
    Default,
}

impl RuntimeConfigSource {
    fn as_str(&self) -> &'static str {
        match self {
            Self::Env => "Env",
            Self::WorkspaceConfig => "WorkspaceConfig",
            Self::Default => "Default",
        }
    }
}

#[derive(Debug, Clone)]
pub struct RuntimeLlmProviderError {
    status: RuntimeLlmProviderStatus,
    message: String,
}

fn task_run_network_allowed() -> bool {
    matches!(
        std::env::var("BROWNIE_LLM_ALLOW_TASK_RUN_NETWORK")
            .ok()
            .as_deref(),
        Some("true")
    )
}

fn task_run_network_guard_reason() -> &'static str {
    "real-provider task.run requires BROWNIE_LLM_ALLOW_TASK_RUN_NETWORK=true"
}

fn llm_status_result(selection: RuntimeLlmProviderStatus) -> LlmStatusResult {
    LlmStatusResult {
        provider: provider_kind_name(&selection.status.provider).to_string(),
        enabled: selection.status.enabled,
        model: selection.status.model,
        base_url: selection.status.base_url,
        reason: selection.status.reason,
        strict: selection.strict,
        will_fallback_to_fake: selection.will_fallback_to_fake,
        config_source: selection.config_source.as_str().to_string(),
        active_profile: selection.active_profile,
        task_run_network_allowed: selection.task_run_network_allowed,
        budget: budget_summary(&selection.budget),
        sensitive_guard: selection.sensitive_guard_mode.as_config_str().to_string(),
    }
}

fn budget_summary(budget: &LlmRequestBudget) -> LlmRequestBudgetSummary {
    LlmRequestBudgetSummary {
        max_prompt_chars: budget.max_prompt_chars,
        max_messages: budget.max_messages,
        request_timeout_ms: budget.request_timeout_ms,
        response_preview_chars: budget.response_preview_chars,
    }
}

fn budget_from_profile(
    profile_budget: Option<&LlmRequestBudgetConfig>,
) -> Result<LlmRequestBudget, String> {
    let mut budget = LlmRequestBudget::default();
    if let Some(profile_budget) = profile_budget {
        budget = profile_budget.apply_to(budget);
    }
    apply_env_budget_overrides(budget)
}

fn provider_default_sensitive_guard(kind: &LlmProviderKind) -> PromptSensitiveGuardMode {
    match kind {
        LlmProviderKind::OpenAiCompatible => PromptSensitiveGuardMode::Fail,
        _ => PromptSensitiveGuardMode::Warn,
    }
}

fn resolve_sensitive_guard(
    provider: &LlmProviderKind,
    profile_value: Option<&String>,
) -> (PromptSensitiveGuardMode, Option<String>) {
    if let Ok(value) = std::env::var("BROWNIE_LLM_SENSITIVE_GUARD") {
        if !value.trim().is_empty() {
            return PromptSensitiveGuardMode::parse(&value)
                .map(|mode| (mode, None))
                .unwrap_or_else(|| {
                    (
                        provider_default_sensitive_guard(provider),
                        Some("BROWNIE_LLM_SENSITIVE_GUARD".to_string()),
                    )
                });
        }
    }
    if let Some(value) = profile_value {
        return PromptSensitiveGuardMode::parse(value)
            .map(|mode| (mode, None))
            .unwrap_or_else(|| {
                (
                    provider_default_sensitive_guard(provider),
                    Some("sensitive_guard".to_string()),
                )
            });
    }
    (provider_default_sensitive_guard(provider), None)
}

fn env_sensitive_guard_override_present() -> bool {
    std::env::var("BROWNIE_LLM_SENSITIVE_GUARD")
        .ok()
        .filter(|v| !v.trim().is_empty())
        .is_some()
}

fn env_budget_override_present() -> bool {
    [
        "BROWNIE_LLM_MAX_PROMPT_CHARS",
        "BROWNIE_LLM_MAX_MESSAGES",
        "BROWNIE_LLM_REQUEST_TIMEOUT_MS",
        "BROWNIE_LLM_RESPONSE_PREVIEW_CHARS",
    ]
    .iter()
    .any(|key| {
        std::env::var(key)
            .ok()
            .filter(|v| !v.trim().is_empty())
            .is_some()
    })
}

fn apply_env_budget_overrides(mut budget: LlmRequestBudget) -> Result<LlmRequestBudget, String> {
    if let Ok(v) = std::env::var("BROWNIE_LLM_MAX_PROMPT_CHARS") {
        if !v.trim().is_empty() {
            budget.max_prompt_chars = v
                .parse()
                .map_err(|_| "invalid BROWNIE_LLM_MAX_PROMPT_CHARS".to_string())?;
        }
    }
    if let Ok(v) = std::env::var("BROWNIE_LLM_MAX_MESSAGES") {
        if !v.trim().is_empty() {
            budget.max_messages = v
                .parse()
                .map_err(|_| "invalid BROWNIE_LLM_MAX_MESSAGES".to_string())?;
        }
    }
    if let Ok(v) = std::env::var("BROWNIE_LLM_REQUEST_TIMEOUT_MS") {
        if !v.trim().is_empty() {
            budget.request_timeout_ms = v
                .parse()
                .map_err(|_| "invalid BROWNIE_LLM_REQUEST_TIMEOUT_MS".to_string())?;
        }
    }
    if let Ok(v) = std::env::var("BROWNIE_LLM_RESPONSE_PREVIEW_CHARS") {
        if !v.trim().is_empty() {
            budget.response_preview_chars = v
                .parse()
                .map_err(|_| "invalid BROWNIE_LLM_RESPONSE_PREVIEW_CHARS".to_string())?;
        }
    }
    validate_llm_request_budget(&budget)?;
    Ok(budget)
}

fn provider_kind_name(kind: &LlmProviderKind) -> &'static str {
    match kind {
        LlmProviderKind::Fake => "Fake",
        LlmProviderKind::OpenAiCompatible => "OpenAiCompatible",
        LlmProviderKind::Unknown => "Unknown",
    }
}

pub fn llm_provider_status_from_workspace(
    workspace_root: &std::path::Path,
) -> Result<RuntimeLlmProviderStatus, String> {
    if env_budget_override_present() {
        budget_from_profile(None)?;
    }
    if std::env::var("BROWNIE_LLM_PROVIDER")
        .ok()
        .filter(|v| !v.trim().is_empty())
        .is_some()
    {
        return Ok(llm_provider_status_from_env());
    }
    let config =
        RuntimeConfigLoader::load_from_workspace(workspace_root).map_err(|e| e.to_string())?;
    if let Some(config) = config {
        return status_from_config(&config);
    }
    Ok(default_fake_status())
}

pub fn llm_provider_status_from_env() -> RuntimeLlmProviderStatus {
    let strict = matches!(
        std::env::var("BROWNIE_LLM_STRICT").ok().as_deref(),
        Some("true")
    );
    match std::env::var("BROWNIE_LLM_PROVIDER").ok().as_deref() {
        Some("openai-compatible") => match OpenAiCompatibleLlmProvider::from_env() {
            OpenAiCompatibleConfigFromEnv::Enabled(config) => RuntimeLlmProviderStatus {
                status: LlmProviderStatus {
                    provider: LlmProviderKind::OpenAiCompatible,
                    enabled: true,
                    model: config.model,
                    base_url: Some(redact_secret(&config.base_url)),
                    reason: None,
                },
                strict,
                will_fallback_to_fake: false,
                config_source: RuntimeConfigSource::Env,
                active_profile: None,
                task_run_network_allowed: task_run_network_allowed(),
                budget: budget_from_profile(None).unwrap_or_default(),
                sensitive_guard_mode: resolve_sensitive_guard(
                    &LlmProviderKind::OpenAiCompatible,
                    None,
                )
                .0,
                sensitive_guard_invalid: resolve_sensitive_guard(
                    &LlmProviderKind::OpenAiCompatible,
                    None,
                )
                .1,
            },
            OpenAiCompatibleConfigFromEnv::Disabled(status) => RuntimeLlmProviderStatus {
                status,
                strict,
                will_fallback_to_fake: !strict,
                config_source: RuntimeConfigSource::Env,
                active_profile: None,
                task_run_network_allowed: task_run_network_allowed(),
                budget: budget_from_profile(None).unwrap_or_default(),
                sensitive_guard_mode: resolve_sensitive_guard(
                    &LlmProviderKind::OpenAiCompatible,
                    None,
                )
                .0,
                sensitive_guard_invalid: resolve_sensitive_guard(
                    &LlmProviderKind::OpenAiCompatible,
                    None,
                )
                .1,
            },
        },
        Some("fake") | None => RuntimeLlmProviderStatus {
            config_source: RuntimeConfigSource::Env,
            ..fake_status_with_profile(None, false)
        },
        Some(value) => RuntimeLlmProviderStatus {
            status: LlmProviderStatus {
                provider: LlmProviderKind::Unknown,
                enabled: false,
                model: String::new(),
                base_url: None,
                reason: Some(format!("unknown provider: {}", redact_secret(value))),
            },
            strict,
            will_fallback_to_fake: !strict,
            config_source: RuntimeConfigSource::Env,
            active_profile: None,
            task_run_network_allowed: task_run_network_allowed(),
            budget: budget_from_profile(None).unwrap_or_default(),
            sensitive_guard_mode: resolve_sensitive_guard(&LlmProviderKind::Unknown, None).0,
            sensitive_guard_invalid: resolve_sensitive_guard(&LlmProviderKind::Unknown, None).1,
        },
    }
}

fn default_fake_status() -> RuntimeLlmProviderStatus {
    RuntimeLlmProviderStatus {
        config_source: RuntimeConfigSource::Default,
        ..fake_status_with_profile(None, false)
    }
}

fn fake_status_with_profile(
    active_profile: Option<String>,
    strict: bool,
) -> RuntimeLlmProviderStatus {
    RuntimeLlmProviderStatus {
        status: FakeLlmProvider.status(),
        strict,
        will_fallback_to_fake: false,
        config_source: RuntimeConfigSource::WorkspaceConfig,
        active_profile,
        task_run_network_allowed: task_run_network_allowed(),
        budget: budget_from_profile(None).unwrap_or_default(),
        sensitive_guard_mode: resolve_sensitive_guard(&LlmProviderKind::Fake, None).0,
        sensitive_guard_invalid: resolve_sensitive_guard(&LlmProviderKind::Fake, None).1,
    }
}

fn status_from_config(config: &BrownieConfig) -> Result<RuntimeLlmProviderStatus, String> {
    let profile_name = config.active_profile.clone().ok_or_else(|| {
        "runtime config active_profile is required when config exists".to_string()
    })?;
    let profile = config
        .llm
        .as_ref()
        .and_then(|l| l.profiles.get(&profile_name))
        .ok_or_else(|| "active_profile references unknown profile".to_string())?;
    Ok(match profile {
        LlmProfile::Fake {
            model,
            budget,
            sensitive_guard,
        } => {
            let mut s = fake_status_with_profile(Some(profile_name), false);
            s.budget = budget_from_profile(budget.as_ref())?;
            let (mode, invalid) =
                resolve_sensitive_guard(&LlmProviderKind::Fake, sensitive_guard.as_ref());
            s.sensitive_guard_mode = mode;
            s.sensitive_guard_invalid = invalid;
            if let Some(model) = model {
                s.status.model = model.clone();
            }
            s
        }
        LlmProfile::OpenAiCompatible {
            base_url,
            model,
            api_key_env,
            strict,
            budget,
            sensitive_guard,
        } => {
            let api_key_env = api_key_env
                .clone()
                .unwrap_or_else(|| "BROWNIE_LLM_API_KEY".to_string());
            let strict = strict.unwrap_or(false);
            let api_key_present = std::env::var(&api_key_env)
                .ok()
                .filter(|v| !v.trim().is_empty())
                .is_some();
            let enabled = api_key_present;
            RuntimeLlmProviderStatus {
                status: LlmProviderStatus {
                    provider: LlmProviderKind::OpenAiCompatible,
                    enabled,
                    model: model.clone(),
                    base_url: Some(redact_secret(base_url)),
                    reason: if enabled {
                        None
                    } else {
                        Some(format!("missing config: {api_key_env}"))
                    },
                },
                strict,
                will_fallback_to_fake: !strict && !enabled,
                config_source: RuntimeConfigSource::WorkspaceConfig,
                active_profile: Some(profile_name),
                task_run_network_allowed: task_run_network_allowed(),
                budget: budget_from_profile(budget.as_ref())?,
                sensitive_guard_mode: resolve_sensitive_guard(
                    &LlmProviderKind::OpenAiCompatible,
                    sensitive_guard.as_ref(),
                )
                .0,
                sensitive_guard_invalid: resolve_sensitive_guard(
                    &LlmProviderKind::OpenAiCompatible,
                    sensitive_guard.as_ref(),
                )
                .1,
            }
        }
    })
}

pub fn llm_provider_from_workspace_for_task_run(
    workspace_root: &std::path::Path,
) -> Result<Box<dyn LlmProvider>, RuntimeLlmProviderError> {
    if std::env::var("BROWNIE_LLM_PROVIDER")
        .ok()
        .filter(|v| !v.trim().is_empty())
        .is_some()
    {
        return llm_provider_from_env_for_task_run();
    }
    let config = RuntimeConfigLoader::load_from_workspace(workspace_root).map_err(|e| {
        RuntimeLlmProviderError {
            status: default_fake_status(),
            message: e.to_string(),
        }
    })?;
    let Some(config) = config else {
        return Ok(Box::new(FakeLlmProvider));
    };
    let selection = status_from_config(&config).map_err(|e| RuntimeLlmProviderError {
        status: default_fake_status(),
        message: e,
    })?;
    if selection.status.provider == LlmProviderKind::Fake {
        return Ok(Box::new(FakeLlmProvider));
    }
    if !selection.status.enabled {
        if selection.strict {
            return Err(RuntimeLlmProviderError {
                message: selection
                    .status
                    .reason
                    .clone()
                    .unwrap_or_else(|| "LLM provider disabled".to_string()),
                status: selection,
            });
        }
        return Ok(Box::new(FakeLlmProvider));
    }
    if !selection.strict {
        return Ok(Box::new(FakeLlmProvider));
    }
    if !selection.task_run_network_allowed {
        return Err(RuntimeLlmProviderError {
            message: task_run_network_guard_reason().to_string(),
            status: selection,
        });
    }
    let profile_name = selection.active_profile.clone().unwrap_or_default();
    let profile = config
        .llm
        .as_ref()
        .and_then(|l| l.profiles.get(&profile_name))
        .expect("validated profile");
    if let LlmProfile::OpenAiCompatible {
        base_url,
        model,
        api_key_env,
        ..
    } = profile
    {
        let api_key_env = api_key_env
            .clone()
            .unwrap_or_else(|| "BROWNIE_LLM_API_KEY".to_string());
        let api_key = std::env::var(&api_key_env).unwrap_or_default();
        Ok(Box::new(OpenAiCompatibleLlmProvider::new(
            OpenAiCompatibleConfig {
                base_url: base_url.clone(),
                model: model.clone(),
                api_key_env,
            },
            api_key,
        )))
    } else {
        Ok(Box::new(FakeLlmProvider))
    }
}

pub fn llm_provider_from_env_for_task_run() -> Result<Box<dyn LlmProvider>, RuntimeLlmProviderError>
{
    match std::env::var("BROWNIE_LLM_PROVIDER").ok().as_deref() {
        Some("openai-compatible") => match OpenAiCompatibleLlmProvider::from_env() {
            OpenAiCompatibleConfigFromEnv::Enabled(config) => {
                let selection = llm_provider_status_from_env();
                if !selection.strict {
                    return Ok(Box::new(FakeLlmProvider));
                }
                if !selection.task_run_network_allowed {
                    return Err(RuntimeLlmProviderError {
                        message: task_run_network_guard_reason().to_string(),
                        status: selection,
                    });
                }
                let api_key = std::env::var(&config.api_key_env).unwrap_or_default();
                Ok(Box::new(OpenAiCompatibleLlmProvider::new(config, api_key)))
            }
            OpenAiCompatibleConfigFromEnv::Disabled(status) => {
                let selection = llm_provider_status_from_env();
                if selection.strict {
                    Err(RuntimeLlmProviderError {
                        message: status
                            .reason
                            .clone()
                            .unwrap_or_else(|| "LLM provider disabled".to_string()),
                        status: selection,
                    })
                } else {
                    Ok(Box::new(FakeLlmProvider))
                }
            }
        },
        Some("fake") | None => Ok(Box::new(FakeLlmProvider)),
        Some(value) => {
            let selection = llm_provider_status_from_env();
            if selection.strict {
                Err(RuntimeLlmProviderError {
                    message: format!("unknown provider: {}", redact_secret(value)),
                    status: selection,
                })
            } else {
                Ok(Box::new(FakeLlmProvider))
            }
        }
    }
}

fn diagnostic(
    severity: DiagnosticSeverity,
    code: &str,
    message: impl Into<String>,
    subject: Option<&str>,
) -> RuntimeDiagnostic {
    RuntimeDiagnostic {
        severity,
        code: code.to_string(),
        message: message.into(),
        subject: subject.map(str::to_string),
    }
}

pub fn runtime_diagnostics_from_workspace(
    workspace_root: &std::path::Path,
) -> RuntimeDiagnosticsResult {
    let mut diagnostics = Vec::new();
    let mut status = match llm_provider_status_from_workspace(workspace_root) {
        Ok(status) => status,
        Err(error) => RuntimeLlmProviderStatus {
            status: LlmProviderStatus {
                provider: LlmProviderKind::Unknown,
                enabled: false,
                model: String::new(),
                base_url: None,
                reason: Some(redact_secret(&error)),
            },
            strict: false,
            will_fallback_to_fake: false,
            config_source: RuntimeConfigSource::WorkspaceConfig,
            active_profile: None,
            task_run_network_allowed: task_run_network_allowed(),
            budget: budget_from_profile(None).unwrap_or_default(),
            sensitive_guard_mode: resolve_sensitive_guard(&LlmProviderKind::Unknown, None).0,
            sensitive_guard_invalid: resolve_sensitive_guard(&LlmProviderKind::Unknown, None).1,
        },
    };

    match llm_provider_status_from_workspace(workspace_root) {
        Ok(selection) => {
            let code = if env_budget_override_present() {
                "LLM_BUDGET_ENV_OVERRIDE"
            } else if selection.config_source == RuntimeConfigSource::WorkspaceConfig {
                "LLM_BUDGET_PROFILE"
            } else {
                "LLM_BUDGET_DEFAULT"
            };
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Info,
                code,
                format!(
                    "LLM request budget: max_prompt_chars={} max_messages={} request_timeout_ms={} response_preview_chars={}",
                    selection.budget.max_prompt_chars, selection.budget.max_messages, selection.budget.request_timeout_ms, selection.budget.response_preview_chars
                ),
                None,
            ));
        }
        Err(error)
            if error.contains("BROWNIE_LLM_")
                || error.contains("budget")
                || error.contains("max_")
                || error.contains("request_timeout_ms")
                || error.contains("response_preview_chars") =>
        {
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Error,
                "LLM_BUDGET_INVALID",
                format!("Invalid LLM request budget: {}.", redact_secret(&error)),
                None,
            ));
            status.status.enabled = false;
            status.status.reason = Some("invalid LLM request budget".to_string());
        }
        Err(_) => {}
    }

    if let Some(subject) = status.sensitive_guard_invalid.clone() {
        diagnostics.push(diagnostic(
            DiagnosticSeverity::Error,
            "PROMPT_SENSITIVE_GUARD_INVALID",
            "Invalid prompt sensitive guard value; expected off, warn, or fail.",
            Some(&subject),
        ));
        status.status.enabled = false;
        status.status.reason = Some("invalid prompt sensitive guard".to_string());
    } else {
        let (code, subject) = if env_sensitive_guard_override_present() {
            (
                "PROMPT_SENSITIVE_GUARD_ENV_OVERRIDE",
                Some("BROWNIE_LLM_SENSITIVE_GUARD"),
            )
        } else if status.config_source == RuntimeConfigSource::WorkspaceConfig {
            (
                "PROMPT_SENSITIVE_GUARD_PROFILE",
                status.active_profile.as_deref(),
            )
        } else {
            ("PROMPT_SENSITIVE_GUARD_DEFAULT", None)
        };
        diagnostics.push(diagnostic(
            DiagnosticSeverity::Info,
            code,
            format!(
                "Prompt sensitive guard mode: {}.",
                status.sensitive_guard_mode.as_config_str()
            ),
            subject,
        ));
    }

    let strict_env = matches!(
        std::env::var("BROWNIE_LLM_STRICT").ok().as_deref(),
        Some("true")
    );
    let env_provider = std::env::var("BROWNIE_LLM_PROVIDER")
        .ok()
        .filter(|v| !v.trim().is_empty());
    if let Some(provider) = env_provider.as_deref() {
        diagnostics.push(diagnostic(
            DiagnosticSeverity::Info,
            "PROVIDER_ENV_OVERRIDE",
            format!(
                "Using LLM provider override from BROWNIE_LLM_PROVIDER: {}.",
                redact_secret(provider)
            ),
            Some("BROWNIE_LLM_PROVIDER"),
        ));
        if !matches!(provider, "fake" | "openai-compatible") {
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Error,
                "PROVIDER_UNKNOWN",
                format!("Unknown LLM provider: {}.", redact_secret(provider)),
                Some("BROWNIE_LLM_PROVIDER"),
            ));
            if strict_env {
                diagnostics.push(diagnostic(
                    DiagnosticSeverity::Error,
                    "PROVIDER_STRICT_FAILURE",
                    "Strict mode will fail task.run for this provider configuration.",
                    Some("BROWNIE_LLM_STRICT"),
                ));
            } else {
                diagnostics.push(diagnostic(
                    DiagnosticSeverity::Warning,
                    "PROVIDER_FALLBACK_TO_FAKE",
                    "Unknown provider will fall back to Fake because strict mode is disabled.",
                    Some("BROWNIE_LLM_PROVIDER"),
                ));
            }
        }
    } else {
        let path = workspace_root.join(CONFIG_RELATIVE_PATH);
        if !path.exists() {
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Info,
                "CONFIG_NOT_FOUND",
                "No .brownie/config.json found; using default Fake provider.",
                Some(CONFIG_RELATIVE_PATH),
            ));
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Info,
                "PROVIDER_DEFAULT_FAKE",
                "Using default Fake LLM provider.",
                None,
            ));
        } else {
            match std::fs::read_to_string(&path) {
                Err(e) => diagnostics.push(diagnostic(
                    DiagnosticSeverity::Error,
                    "CONFIG_MALFORMED",
                    format!("Failed to read .brownie/config.json: {e}"),
                    Some(CONFIG_RELATIVE_PATH),
                )),
                Ok(content) => match serde_json::from_str::<serde_json::Value>(&content) {
                    Err(e) => diagnostics.push(diagnostic(
                        DiagnosticSeverity::Error,
                        "CONFIG_MALFORMED",
                        format!("Failed to parse .brownie/config.json: {e}"),
                        Some(CONFIG_RELATIVE_PATH),
                    )),
                    Ok(value) => {
                        if contains_key_recursive(&value, "api_key") {
                            diagnostics.push(diagnostic(
                                DiagnosticSeverity::Error,
                                "CONFIG_DIRECT_API_KEY_REJECTED",
                                "Direct api_key fields are not allowed; use api_key_env.",
                                Some(CONFIG_RELATIVE_PATH),
                            ));
                        }
                        match serde_json::from_value::<BrownieConfig>(value) {
                            Err(e) => diagnostics.push(diagnostic(
                                DiagnosticSeverity::Error,
                                "CONFIG_MALFORMED",
                                format!("Failed to validate .brownie/config.json: {e}"),
                                Some(CONFIG_RELATIVE_PATH),
                            )),
                            Ok(config) => {
                                if config.version != 1 {
                                    diagnostics.push(diagnostic(
                                        DiagnosticSeverity::Error,
                                        "CONFIG_UNSUPPORTED_VERSION",
                                        format!(
                                            "Unsupported runtime config version: {}.",
                                            config.version
                                        ),
                                        Some(CONFIG_RELATIVE_PATH),
                                    ));
                                }
                                match config.active_profile.as_deref() {
                                    None => diagnostics.push(diagnostic(
                                        DiagnosticSeverity::Error,
                                        "ACTIVE_PROFILE_MISSING",
                                        "active_profile is required when config exists.",
                                        Some(CONFIG_RELATIVE_PATH),
                                    )),
                                    Some(active) => {
                                        let profile = config
                                            .llm
                                            .as_ref()
                                            .and_then(|l| l.profiles.get(active));
                                        if profile.is_none() {
                                            diagnostics.push(diagnostic(DiagnosticSeverity::Error, "ACTIVE_PROFILE_UNKNOWN", format!("active_profile references unknown profile: {active}."), Some("active_profile")));
                                        } else {
                                            diagnostics.push(diagnostic(
                                                DiagnosticSeverity::Info,
                                                "PROVIDER_WORKSPACE_PROFILE",
                                                format!("Using workspace LLM profile {active}."),
                                                Some(active),
                                            ));
                                            if let Some(LlmProfile::OpenAiCompatible {
                                                api_key_env,
                                                strict,
                                                ..
                                            }) = profile
                                            {
                                                let key_env =
                                                    api_key_env.clone().unwrap_or_else(|| {
                                                        "BROWNIE_LLM_API_KEY".to_string()
                                                    });
                                                let key_present = std::env::var(&key_env)
                                                    .ok()
                                                    .filter(|v| !v.trim().is_empty())
                                                    .is_some();
                                                if !key_present {
                                                    diagnostics.push(diagnostic(DiagnosticSeverity::Warning, "API_KEY_ENV_MISSING", format!("API key environment variable is not set: {key_env}."), Some(&key_env)));
                                                    if strict.unwrap_or(false) {
                                                        diagnostics.push(diagnostic(DiagnosticSeverity::Error, "PROVIDER_STRICT_FAILURE", "Strict mode will fail task.run for this provider configuration.", Some("strict")));
                                                    } else {
                                                        diagnostics.push(diagnostic(DiagnosticSeverity::Warning, "PROVIDER_FALLBACK_TO_FAKE", "OpenAI-compatible provider will fall back to Fake because strict mode is disabled.", Some(active)));
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                },
            }
        }
    }

    if status.status.provider == LlmProviderKind::OpenAiCompatible
        && status.status.enabled
        && status.strict
    {
        if status.task_run_network_allowed {
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Info,
                "TASK_RUN_NETWORK_ALLOWED",
                "OpenAI-compatible task.run network calls are explicitly allowed.",
                Some("BROWNIE_LLM_ALLOW_TASK_RUN_NETWORK"),
            ));
        } else {
            diagnostics.push(diagnostic(
                DiagnosticSeverity::Warning,
                "TASK_RUN_NETWORK_NOT_ALLOWED",
                task_run_network_guard_reason(),
                Some("BROWNIE_LLM_ALLOW_TASK_RUN_NETWORK"),
            ));
        }
    }

    if diagnostics.iter().any(|d| {
        d.code == "CONFIG_DIRECT_API_KEY_REJECTED"
            || d.code == "CONFIG_MALFORMED"
            || d.code == "CONFIG_UNSUPPORTED_VERSION"
            || d.code == "ACTIVE_PROFILE_UNKNOWN"
            || d.code == "ACTIVE_PROFILE_MISSING"
    }) {
        status.status.provider = LlmProviderKind::Unknown;
        status.status.enabled = false;
        status.status.model.clear();
        status.status.base_url = None;
        status.will_fallback_to_fake = false;
    }

    RuntimeDiagnosticsResult {
        config_source: status.config_source.as_str().to_string(),
        active_profile: status.active_profile.clone(),
        llm_status: llm_status_result(status),
        parser_config: tool_intent_parser_config_summary(),
        diagnostics,
    }
}

pub fn llm_health_from_workspace(
    workspace_root: &std::path::Path,
    allow_network: bool,
    timeout: std::time::Duration,
) -> Result<LlmHealthResult, String> {
    let selection = llm_provider_status_from_workspace(workspace_root)?;
    let checked_at = time::OffsetDateTime::now_utc()
        .format(&time::format_description::well_known::Rfc3339)
        .map_err(|e| e.to_string())?;
    let mut result = LlmHealthResult {
        provider: provider_kind_name(&selection.status.provider).to_string(),
        config_source: selection.config_source.as_str().to_string(),
        active_profile: selection.active_profile.clone(),
        enabled: selection.status.enabled,
        attempted: false,
        healthy: false,
        model: selection.status.model.clone(),
        base_url: selection.status.base_url.clone(),
        checked_at,
        latency_ms: None,
        status_code: None,
        reason: selection.status.reason.clone().map(|v| redact_secret(&v)),
        diagnostics: Vec::new(),
    };

    match selection.status.provider {
        LlmProviderKind::Fake => {
            result.enabled = true;
            result.healthy = true;
            result.reason = None;
            result.diagnostics.push(diagnostic(
                DiagnosticSeverity::Info,
                "PROVIDER_FAKE_HEALTHY",
                "Fake provider is healthy without network access.",
                None,
            ));
            Ok(result)
        }
        LlmProviderKind::OpenAiCompatible if !selection.status.enabled => {
            result.diagnostics.push(diagnostic(
                DiagnosticSeverity::Error,
                "HEALTH_PROVIDER_DISABLED",
                selection
                    .status
                    .reason
                    .clone()
                    .unwrap_or_else(|| "OpenAI-compatible provider is disabled.".to_string()),
                None,
            ));
            Ok(result)
        }
        LlmProviderKind::OpenAiCompatible if !allow_network => {
            result.diagnostics.push(diagnostic(
                DiagnosticSeverity::Warning,
                "HEALTH_NETWORK_NOT_ALLOWED",
                "Network probe was not attempted because allow_network=false.",
                None,
            ));
            Ok(result)
        }
        LlmProviderKind::OpenAiCompatible => {
            let provider = openai_provider_from_workspace_for_health(workspace_root, &selection)?;
            let probe = provider.probe_models(timeout);
            result.attempted = probe.attempted;
            result.healthy = probe.healthy;
            result.latency_ms = probe.latency_ms;
            result.status_code = probe.status_code;
            result.reason = probe.reason.map(|v| redact_secret(&v));
            result.diagnostics.push(diagnostic(
                if result.healthy {
                    DiagnosticSeverity::Info
                } else {
                    DiagnosticSeverity::Error
                },
                if result.healthy {
                    "HEALTH_PROBE_OK"
                } else {
                    "HEALTH_PROBE_FAILED"
                },
                if result.healthy {
                    "OpenAI-compatible /models probe returned a 2xx status.".to_string()
                } else {
                    result
                        .reason
                        .clone()
                        .unwrap_or_else(|| "OpenAI-compatible /models probe failed.".to_string())
                },
                result.base_url.as_deref(),
            ));
            Ok(result)
        }
        LlmProviderKind::Unknown => {
            result.diagnostics.push(diagnostic(
                DiagnosticSeverity::Error,
                "HEALTH_PROVIDER_UNSUPPORTED",
                selection
                    .status
                    .reason
                    .clone()
                    .unwrap_or_else(|| "Unsupported LLM provider.".to_string()),
                None,
            ));
            Ok(result)
        }
    }
}

fn openai_provider_from_workspace_for_health(
    workspace_root: &std::path::Path,
    selection: &RuntimeLlmProviderStatus,
) -> Result<OpenAiCompatibleLlmProvider, String> {
    if selection.config_source == RuntimeConfigSource::Env {
        return match OpenAiCompatibleLlmProvider::from_env() {
            OpenAiCompatibleConfigFromEnv::Enabled(config) => {
                let api_key = std::env::var(&config.api_key_env).unwrap_or_default();
                Ok(OpenAiCompatibleLlmProvider::new(config, api_key))
            }
            OpenAiCompatibleConfigFromEnv::Disabled(status) => Err(status
                .reason
                .unwrap_or_else(|| "OpenAI-compatible provider disabled".to_string())),
        };
    }
    let config =
        RuntimeConfigLoader::load_from_workspace(workspace_root).map_err(|e| e.to_string())?;
    let config = config.ok_or_else(|| "workspace config missing".to_string())?;
    let profile_name = selection.active_profile.clone().unwrap_or_default();
    let profile = config
        .llm
        .as_ref()
        .and_then(|llm| llm.profiles.get(&profile_name))
        .ok_or_else(|| "active_profile references unknown profile".to_string())?;
    let LlmProfile::OpenAiCompatible {
        base_url,
        model,
        api_key_env,
        ..
    } = profile
    else {
        return Err("active provider is not OpenAI-compatible".to_string());
    };
    let api_key_env = api_key_env
        .clone()
        .unwrap_or_else(|| "BROWNIE_LLM_API_KEY".to_string());
    let api_key =
        std::env::var(&api_key_env).map_err(|_| format!("missing config: {api_key_env}"))?;
    Ok(OpenAiCompatibleLlmProvider::new(
        OpenAiCompatibleConfig {
            base_url: base_url.clone(),
            model: model.clone(),
            api_key_env,
        },
        api_key,
    ))
}

fn contains_key_recursive(value: &serde_json::Value, key: &str) -> bool {
    match value {
        serde_json::Value::Object(map) => map
            .iter()
            .any(|(k, v)| k == key || contains_key_recursive(v, key)),
        serde_json::Value::Array(items) => items.iter().any(|v| contains_key_recursive(v, key)),
        _ => false,
    }
}

fn handle_llm_status(id: Value) -> JsonRpcResponse<Value> {
    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    match llm_provider_status_from_workspace(store.workspace_root()) {
        Ok(status) => result_response(id, json!(llm_status_result(status))),
        Err(error) => error_response(
            id,
            -32603,
            &format!("internal error: {}", redact_secret(&error)),
        ),
    }
}

fn handle_runtime_diagnostics_get(id: Value) -> JsonRpcResponse<Value> {
    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    result_response(
        id,
        json!(runtime_diagnostics_from_workspace(store.workspace_root())),
    )
}

fn handle_llm_health(id: Value, params: Option<Value>) -> JsonRpcResponse<Value> {
    let params: LlmHealthParams = match parse_params(params) {
        Ok(params) => params,
        Err(message) => return error_response(id, -32602, &message),
    };
    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let default_timeout_ms = llm_provider_status_from_workspace(store.workspace_root())
        .map(|selection| selection.budget.request_timeout_ms)
        .unwrap_or(30_000);
    let timeout_ms = params.timeout_ms.unwrap_or(default_timeout_ms);
    if !(1000..=300000).contains(&timeout_ms) {
        return error_response(
            id,
            -32602,
            "invalid params: timeout_ms must be between 1000 and 300000",
        );
    }
    match llm_health_from_workspace(
        store.workspace_root(),
        params.allow_network,
        std::time::Duration::from_millis(timeout_ms),
    ) {
        Ok(result) => result_response(id, json!(result)),
        Err(error) => error_response(
            id,
            -32603,
            &format!("internal error: {}", redact_secret(&error)),
        ),
    }
}

fn handle_runtime_config_get(id: Value) -> JsonRpcResponse<Value> {
    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let status = match llm_provider_status_from_workspace(store.workspace_root()) {
        Ok(status) => status,
        Err(error) => {
            return error_response(
                id,
                -32603,
                &format!("internal error: {}", redact_secret(&error)),
            )
        }
    };
    let result = RuntimeConfigGetResult {
        config_source: status.config_source.as_str().to_string(),
        config_path: if status.config_source == RuntimeConfigSource::WorkspaceConfig {
            Some(CONFIG_RELATIVE_PATH.to_string())
        } else {
            None
        },
        active_profile: status.active_profile.clone(),
        llm_status: llm_status_result(status),
    };
    result_response(id, json!(result))
}

fn handle_task_start(id: Value, params: Option<Value>) -> JsonRpcResponse<Value> {
    let params: TaskStartParams = match parse_params(params) {
        Ok(params) => params,
        Err(message) => return error_response(id, -32602, &message),
    };
    let TaskStartParams {
        goal,
        mode_id,
        verification_recovery_source,
        verification_recovery_retry_source,
    } = params;

    if goal.trim().is_empty() {
        return error_response(id, -32602, "invalid params: goal must not be empty");
    }

    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };

    let policy = match resolve_task_start_policy(mode_id.as_deref(), &store) {
        Ok(policy) => policy,
        Err(message) => return error_response(id, -32602, &message),
    };

    if verification_recovery_source.is_some() && verification_recovery_retry_source.is_some() {
        return error_response(
            id,
            -32602,
            "invalid params: specify only one verification recovery source envelope",
        );
    }

    if let Some(source) = verification_recovery_source {
        let provenance = match verification_recovery_provenance_for_source(&store, &source) {
            Ok(provenance) => provenance,
            Err(VerificationRecoveryAdmissionError::InvalidParams(message)) => {
                return error_response(id, -32602, &message)
            }
            Err(VerificationRecoveryAdmissionError::Internal(message)) => {
                return error_response(id, -32603, &format!("internal error: {message}"))
            }
        };
        let failure_fingerprint = provenance.failure_fingerprint.clone();
        match store
            .tasks()
            .start_verification_recovery_task(VerificationRecoveryTaskStartParams {
                goal,
                mode_id: Some(policy.mode_id.clone()),
                provenance,
            }) {
            Ok(admission) => {
                if !admission.replayed {
                    if let Err(error) = store.tasks().append_task_event_with_payload(
                        &admission.record,
                        LedgerEventKind::ModeResolved,
                        Some(mode_resolved_payload(&policy)),
                    ) {
                        return error_response(id, -32603, &format!("internal error: {error}"));
                    }
                }
                result_response(
                    id,
                    json!(TaskStartResult {
                        task_id: admission.record.task_id.clone(),
                        run_id: admission.record.run_id.clone(),
                        status: admission.record.status.clone(),
                        verification_recovery_admission: Some(VerificationRecoveryAdmission {
                            source_task_id: source.source_task_id,
                            source_run_id: source.source_run_id,
                            recovery_task_id: admission.record.task_id,
                            recovery_run_id: admission.record.run_id,
                            failure_fingerprint,
                            recovery_running_enabled: false,
                            next_action: "run_recovery_task_explicitly".into(),
                            replayed: admission.replayed,
                        }),
                        verification_recovery_retry_admission: None,
                    }),
                )
            }
            Err(error) => error_response(id, -32603, &format!("internal error: {error}")),
        }
    } else if let Some(source) = verification_recovery_retry_source {
        let provenance = match verification_recovery_retry_provenance_for_source(&store, &source) {
            Ok(provenance) => provenance,
            Err(VerificationRecoveryAdmissionError::InvalidParams(message)) => {
                return error_response(id, -32602, &message)
            }
            Err(VerificationRecoveryAdmissionError::Internal(message)) => {
                return error_response(id, -32603, &format!("internal error: {message}"))
            }
        };
        let failure_fingerprint = provenance.failure_fingerprint.clone();
        let apply_fingerprint = provenance.apply_fingerprint.clone();
        match store.tasks().start_verification_recovery_retry_task(
            VerificationRecoveryRetryTaskStartParams {
                goal,
                mode_id: Some(policy.mode_id.clone()),
                provenance,
            },
        ) {
            Ok(admission) => {
                if !admission.replayed {
                    if let Err(error) = store.tasks().append_task_event_with_payload(
                        &admission.record,
                        LedgerEventKind::ModeResolved,
                        Some(mode_resolved_payload(&policy)),
                    ) {
                        return error_response(id, -32603, &format!("internal error: {error}"));
                    }
                }
                result_response(
                    id,
                    json!(TaskStartResult {
                        task_id: admission.record.task_id.clone(),
                        run_id: admission.record.run_id.clone(),
                        status: admission.record.status.clone(),
                        verification_recovery_admission: None,
                        verification_recovery_retry_admission: Some(
                            VerificationRecoveryRetryAdmission {
                                source_task_id: source.source_task_id,
                                source_run_id: source.source_run_id,
                                recovery_task_id: source.recovery_task_id,
                                recovery_run_id: source.recovery_run_id,
                                retry_task_id: admission.record.task_id,
                                retry_run_id: admission.record.run_id,
                                proposal_id: source.proposal_id,
                                apply_id: source.apply_id,
                                failure_fingerprint,
                                apply_fingerprint,
                                retry_running_enabled: false,
                                next_action: "run_verification_retry_task_explicitly".into(),
                                replayed: admission.replayed,
                            }
                        ),
                    }),
                )
            }
            Err(error) => error_response(id, -32603, &format!("internal error: {error}")),
        }
    } else {
        let params = TaskStartParams {
            goal,
            mode_id: Some(policy.mode_id.clone()),
            verification_recovery_source: None,
            verification_recovery_retry_source: None,
        };

        match store.tasks().start_task(params) {
            Ok(record) => {
                if let Err(error) = store.tasks().append_task_event_with_payload(
                    &record,
                    LedgerEventKind::ModeResolved,
                    Some(mode_resolved_payload(&policy)),
                ) {
                    return error_response(id, -32603, &format!("internal error: {error}"));
                }
                result_response(
                    id,
                    json!(TaskStartResult {
                        task_id: record.task_id,
                        run_id: record.run_id,
                        status: record.status,
                        verification_recovery_admission: None,
                        verification_recovery_retry_admission: None,
                    }),
                )
            }
            Err(error) => error_response(id, -32603, &format!("internal error: {error}")),
        }
    }
}

fn handle_task_get(id: Value, params: Option<Value>) -> JsonRpcResponse<Value> {
    let params: TaskGetParams = match parse_params(params) {
        Ok(params) => params,
        Err(message) => return error_response(id, -32602, &message),
    };

    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };

    match store.tasks().get_task(&params.task_id) {
        Ok(Some(record)) => result_response(id, json!(record)),
        Ok(None) => error_response(id, -32602, "invalid params: task not found"),
        Err(error) => error_response(id, -32603, &format!("internal error: {error}")),
    }
}

fn handle_task_run(id: Value, params: Option<Value>) -> JsonRpcResponse<Value> {
    let params: TaskRunParams = match parse_params(params) {
        Ok(params) => params,
        Err(message) => return error_response(id, -32602, &message),
    };

    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };

    let record = match store.tasks().get_task(&params.task_id) {
        Ok(Some(record)) => record,
        Ok(None) => return error_response(id, -32602, "invalid params: task not found"),
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };

    match verification_recovery_repair_outcome_for_replay(&store, &record) {
        Ok(Some((agent_loop, verification_recovery_repair))) => {
            return result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop,
                    verification_completion_gate: None,
                    verification_recovery_repair: Some(verification_recovery_repair),
                    verification_recovery_retry: None,
                    recovery_cycle_budget_outcome: None,
                    child_orchestration_outcome: None,
                    parent_join_readiness_outcome: None,
                }),
            );
        }
        Ok(None) => {}
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    }

    match verification_recovery_retry_outcome_for_replay(&store, &record) {
        Ok(Some((agent_loop, verification_completion_gate, verification_recovery_retry))) => {
            return result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop,
                    verification_completion_gate,
                    verification_recovery_repair: None,
                    verification_recovery_retry: Some(verification_recovery_retry),
                    recovery_cycle_budget_outcome: None,
                    child_orchestration_outcome: None,
                    parent_join_readiness_outcome: None,
                }),
            );
        }
        Ok(None) => {}
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    }

    if record.verification_recovery_retry_provenance.is_some() {
        return handle_verification_recovery_retry_task_run(id, store, record);
    }

    match recovery_cycle_budget_outcome_for_replay(&store, &record) {
        Ok(Some((agent_loop, recovery_cycle_budget_outcome))) => {
            return result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop,
                    verification_completion_gate: None,
                    verification_recovery_repair: None,
                    verification_recovery_retry: None,
                    recovery_cycle_budget_outcome: Some(recovery_cycle_budget_outcome),
                    child_orchestration_outcome: None,
                    parent_join_readiness_outcome: None,
                }),
            );
        }
        Ok(None) => {}
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    }

    match child_orchestration_outcome_for_replay(&store, &record) {
        Ok(Some((agent_loop, child_orchestration_outcome))) => {
            return result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop,
                    verification_completion_gate: None,
                    verification_recovery_repair: None,
                    verification_recovery_retry: None,
                    recovery_cycle_budget_outcome: None,
                    child_orchestration_outcome: Some(child_orchestration_outcome),
                    parent_join_readiness_outcome: None,
                }),
            );
        }
        Ok(None) => {}
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    }

    match parent_join_readiness_outcome_for_replay(&store, &record) {
        Ok(Some((agent_loop, parent_join_readiness_outcome))) => {
            return result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop,
                    verification_completion_gate: None,
                    verification_recovery_repair: None,
                    verification_recovery_retry: None,
                    recovery_cycle_budget_outcome: None,
                    child_orchestration_outcome: None,
                    parent_join_readiness_outcome: Some(parent_join_readiness_outcome),
                }),
            );
        }
        Ok(None) => {}
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    }

    let is_verification_recovery_task =
        match revalidate_verification_recovery_task_for_run(&store, &record) {
            Ok(value) => value,
            Err(rejection) => {
                return match rejection {
                    TaskRunAdmissionRejection::InvalidParams(message) => {
                        error_response(id, -32602, message)
                    }
                    TaskRunAdmissionRejection::Internal(message) => {
                        error_response(id, -32603, &format!("internal error: {message}"))
                    }
                }
            }
        };

    let admission = match validate_task_run_admission(&record, &store) {
        Ok(admission) => admission,
        Err(rejection) => {
            return match rejection {
                TaskRunAdmissionRejection::InvalidParams(message) => {
                    error_response(id, -32602, message)
                }
                TaskRunAdmissionRejection::Internal(message) => {
                    error_response(id, -32603, &format!("internal error: {message}"))
                }
            }
        }
    };
    let child_completion_summaries = admission.child_completion_summaries();
    let mut parent_join_continuation = admission.parent_join_continuation_materialization();

    let running = match admission.parent_join_continuation_consumption() {
        Some(consumption) => match store.tasks().admit_parent_join_continuation(
            &record.task_id,
            ParentJoinContinuationRunAdmission {
                child_completion_fingerprint: consumption.child_completion_fingerprint,
                child_completion_child_count: consumption.child_completion_child_count,
                child_completion_fingerprint_input_count: consumption
                    .child_completion_fingerprint_input_count,
                child_terminal_completed_count: consumption.child_terminal_completed_count,
                child_terminal_failed_count: consumption.child_terminal_failed_count,
                child_recovery_cycle_depth: consumption.child_recovery_cycle_depth,
            },
        ) {
            Ok(Some(admitted)) => {
                if let Some(continuation) = parent_join_continuation.as_mut() {
                    continuation.admission_id = admitted.admission_id.clone();
                }
                admitted.record
            }
            Ok(None) => {
                return error_response(
                    id,
                    -32602,
                    "invalid params: parent join continuation for this completed child result set has already been consumed",
                );
            }
            Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
        },
        None => match store.tasks().update_task_status(
            &record.task_id,
            TaskStatus::Running,
            LedgerEventKind::TaskRunning,
        ) {
            Ok(record) => record,
            Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
        },
    };

    let policy = match resolve_policy_for_task_run(&running, &store) {
        Ok(policy) => policy,
        Err(message) => return error_response(id, -32603, &format!("internal error: {message}")),
    };

    if let Err(error) = append_permission_checks(&store, &running, &policy) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_tool_plan_events(&store, &running, &policy) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }

    let ledger_events = match store.tasks().read_ledger_events(&running.run_id) {
        Ok(events) => events,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let prompt_input = ContextMaterializer::materialize(ContextMaterializerInput {
        task: running.clone(),
        ledger_events,
        child_completion_summaries: child_completion_summaries.clone(),
    });
    let prompt_context_window = prompt_input.context_window.clone();
    let provider = match llm_provider_from_workspace_for_task_run(store.workspace_root()) {
        Ok(provider) => provider,
        Err(error) => {
            return fail_llm_request(
                &store,
                &running,
                id,
                error.status,
                &error.message,
                LedgerEventKind::LlmRequestFailed,
            );
        }
    };
    let provider_status = provider.status();
    let provider_selection = match llm_provider_status_from_workspace(store.workspace_root()) {
        Ok(s) => s,
        Err(error) => {
            return error_response(
                id,
                -32603,
                &format!("internal error: {}", redact_secret(&error)),
            )
        }
    };
    let provider_strict = provider_selection.strict;
    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::AgentLoopStarted,
        Some(json!({
            "entrypoint": METHOD_TASK_RUN,
            "state": agent_loop_state_name(AgentLoopState::BuildingContext),
        })),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    let result = match AgentLoop::run_with_llm(
        prompt_input,
        provider.as_ref(),
        &provider_selection.budget,
        provider_selection.sensitive_guard_mode.clone(),
    ) {
        Ok(result) => result,
        Err(error) => {
            return fail_llm_request(
                &store,
                &running,
                id,
                RuntimeLlmProviderStatus {
                    status: provider_status.clone(),
                    strict: provider_strict,
                    will_fallback_to_fake: false,
                    config_source: provider_selection.config_source.clone(),
                    active_profile: provider_selection.active_profile.clone(),
                    task_run_network_allowed: provider_selection.task_run_network_allowed,
                    budget: provider_selection.budget.clone(),
                    sensitive_guard_mode: provider_selection.sensitive_guard_mode.clone(),
                    sensitive_guard_invalid: provider_selection.sensitive_guard_invalid.clone(),
                },
                &error.to_string(),
                LedgerEventKind::LlmRequestFailed,
            );
        }
    };
    let mut agent_loop_final_state = result.final_state;
    let mut agent_loop_completion_summary = result.completion_summary.clone();
    let mut agent_loop_final_response_content = result.llm_response.content.clone();

    if let Err(error) = append_sensitive_scan_event(
        &store,
        &running,
        &result.sensitive_scan,
        &provider_selection.sensitive_guard_mode,
        false,
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }

    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::PromptBuilt,
        Some(prompt_built_payload(
            result.prompt.messages.len(),
            &result.prompt,
            provider_selection.budget.response_preview_chars,
            provider_selection.budget.max_prompt_chars,
            &result.sensitive_scan,
            &prompt_context_window,
        )),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::LlmRequestCreated,
        Some(json!({
            "provider": provider_kind_name(&provider_status.provider),
            "model": result.llm_request.model.clone(),
            "message_count": result.llm_request.messages.len(),
            "base_url": provider_status.base_url.as_deref().map(redact_secret),
            "strict": provider_strict,
        })),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) =
        append_tool_intent_events(&store, &running, &policy, &result.llm_response.content)
    {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) =
        handle_approved_workspace_intents(&store, &running, &policy, &result.llm_response.content)
    {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    let verification_recovery_repair = if is_verification_recovery_task {
        match verification_recovery_repair_outcome_for_run(&store, &running, false) {
            Ok(outcome) => outcome,
            Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
        }
    } else {
        None
    };
    if let Err(error) = append_subtask_handoff_prepared(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_scheduler_readiness_recorded(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_plan_prepared(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_contract_prepared(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_admission_evaluated(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_readiness_snapshot_recorded(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatcher_guard_verdict_recorded(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_decision_recorded(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_candidate_manifest_recorded(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_subtask_dispatch_handoff_envelope_recorded(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Some(continuation) = parent_join_continuation.as_ref() {
        if let Err(error) = append_parent_join_continuation_handoff_envelope_recorded(
            &store,
            &running,
            continuation,
        ) {
            return error_response(id, -32603, &format!("internal error: {error}"));
        }
    }
    let child_task_ids_before_materialization =
        match child_task_ids_for_parent_run(&store, &running.run_id) {
            Ok(child_task_ids) => child_task_ids,
            Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
        };
    if let Err(error) = materialize_controlled_child_task_from_handoff_envelope(&store, &running) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    let child_orchestration_outcome = match child_orchestration_outcome_for_materialized_children(
        &store,
        &running.run_id,
        &child_task_ids_before_materialization,
    ) {
        Ok(outcome) => outcome,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };

    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::LlmResponseReceived,
        Some(json!({
            "provider": provider_kind_name(&provider_status.provider),
            "content_preview": preview_with_limit(&result.llm_response.content, provider_selection.budget.response_preview_chars),
            "response_preview_chars": provider_selection.budget.response_preview_chars,
        })),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }

    let second_pass_events = match store.tasks().read_ledger_events(&running.run_id) {
        Ok(events) => events,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    if second_pass_events
        .iter()
        .any(|event| event.kind == LedgerEventKind::ToolExecutionCompleted)
    {
        let second_pass_prompt_input = ContextMaterializer::materialize(ContextMaterializerInput {
            task: running.clone(),
            ledger_events: second_pass_events,
            child_completion_summaries: child_completion_summaries.clone(),
        });
        let second_pass_context_window = second_pass_prompt_input.context_window.clone();
        let second_pass = match AgentLoop::run_second_pass_with_llm(
            second_pass_prompt_input,
            provider.as_ref(),
            &provider_selection.budget,
            provider_selection.sensitive_guard_mode.clone(),
        ) {
            Ok(result) => result,
            Err(error) => {
                return fail_llm_request(
                    &store,
                    &running,
                    id,
                    RuntimeLlmProviderStatus {
                        status: provider_status.clone(),
                        strict: provider_strict,
                        will_fallback_to_fake: false,
                        config_source: provider_selection.config_source.clone(),
                        active_profile: provider_selection.active_profile.clone(),
                        task_run_network_allowed: provider_selection.task_run_network_allowed,
                        budget: provider_selection.budget.clone(),
                        sensitive_guard_mode: provider_selection.sensitive_guard_mode.clone(),
                        sensitive_guard_invalid: provider_selection.sensitive_guard_invalid.clone(),
                    },
                    &error.to_string(),
                    LedgerEventKind::SecondPassLlmRequestFailed,
                );
            }
        };
        agent_loop_final_state = second_pass.final_state;
        agent_loop_completion_summary = second_pass.completion_summary.clone();
        agent_loop_final_response_content = second_pass.llm_response.content.clone();
        if let Err(error) = append_sensitive_scan_event(
            &store,
            &running,
            &second_pass.sensitive_scan,
            &provider_selection.sensitive_guard_mode,
            false,
        ) {
            return error_response(id, -32603, &format!("internal error: {error}"));
        }

        if let Err(error) = store.tasks().append_task_event_with_payload(
            &running,
            LedgerEventKind::SecondPassPromptBuilt,
            Some(prompt_built_payload(
                second_pass.prompt.messages.len(),
                &second_pass.prompt,
                provider_selection.budget.response_preview_chars,
                provider_selection.budget.max_prompt_chars,
                &second_pass.sensitive_scan,
                &second_pass_context_window,
            )),
        ) {
            return error_response(id, -32603, &format!("internal error: {error}"));
        }
        if let Err(error) = store.tasks().append_task_event_with_payload(
            &running,
            LedgerEventKind::SecondPassLlmRequestCreated,
            Some(json!({
                "provider": provider_kind_name(&provider_status.provider),
                "model": second_pass.llm_request.model.clone(),
                "message_count": second_pass.llm_request.messages.len(),
                "base_url": provider_status.base_url.as_deref().map(redact_secret),
                "strict": provider_strict,
            })),
        ) {
            return error_response(id, -32603, &format!("internal error: {error}"));
        }
        if let Err(error) = store.tasks().append_task_event_with_payload(
            &running,
            LedgerEventKind::SecondPassLlmResponseReceived,
            Some(json!({
                "provider": provider_kind_name(&provider_status.provider),
                "content_preview": preview_with_limit(&second_pass.llm_response.content, provider_selection.budget.response_preview_chars),
                "response_preview_chars": provider_selection.budget.response_preview_chars,
            })),
        ) {
            return error_response(id, -32603, &format!("internal error: {error}"));
        }
    }

    let completion_gate_events = match store.tasks().read_ledger_events(&running.run_id) {
        Ok(events) => events,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let verification_completion_gate =
        verification_completion_gate_for_run(&completion_gate_events);
    if let Some(gate) = verification_completion_gate.as_ref() {
        if gate.status == VERIFICATION_COMPLETION_GATE_STATUS_FAILED {
            agent_loop_final_state = AgentLoopState::Failed;
            agent_loop_completion_summary = verification_completion_gate_failed_summary(gate);
            agent_loop_final_response_content.clear();
        }
    }

    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::AgentLoopCompleted,
        Some(json!({
            "final_state": agent_loop_state_name(agent_loop_final_state),
            "completion_summary": agent_loop_completion_summary.clone(),
            "completion_result_fingerprint": completion_result_fingerprint(
                agent_loop_final_state,
                &agent_loop_completion_summary,
                &agent_loop_final_response_content,
            ),
        })),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }

    let final_status = match agent_loop_final_state {
        AgentLoopState::Completed => TaskStatus::Completed,
        AgentLoopState::Cancelled => TaskStatus::Cancelled,
        AgentLoopState::Failed => TaskStatus::Failed,
        _ => TaskStatus::Failed,
    };
    let event_kind = match final_status {
        TaskStatus::Completed => LedgerEventKind::TaskCompleted,
        TaskStatus::Cancelled => LedgerEventKind::TaskCancelled,
        TaskStatus::Failed => LedgerEventKind::TaskFailed,
        TaskStatus::Created | TaskStatus::Queued | TaskStatus::Running => {
            LedgerEventKind::TaskFailed
        }
    };

    let recovery_cycle_budget_outcome =
        match recovery_cycle_budget_outcome_for_run(&store, &running.run_id) {
            Ok(outcome) => outcome,
            Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
        };
    let terminal_payload = verification_completion_gate
        .as_ref()
        .map(verification_completion_gate_payload);

    match store.tasks().update_task_status_with_payload(
        &running.task_id,
        final_status,
        event_kind,
        terminal_payload,
    ) {
        Ok(record) => {
            let parent_join_readiness_outcome =
                match parent_join_readiness_outcome_for_terminal_child(&store, &record) {
                    Ok(outcome) => outcome,
                    Err(error) => {
                        return error_response(id, -32603, &format!("internal error: {error}"))
                    }
                };
            result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop: TaskRunAgentLoopSummary {
                        final_state: agent_loop_state_name(agent_loop_final_state).to_string(),
                        completion_summary: agent_loop_completion_summary,
                    },
                    verification_completion_gate,
                    verification_recovery_repair,
                    verification_recovery_retry: None,
                    recovery_cycle_budget_outcome,
                    child_orchestration_outcome,
                    parent_join_readiness_outcome,
                }),
            )
        }
        Err(error) => error_response(id, -32603, &format!("internal error: {error}")),
    }
}

fn handle_verification_recovery_retry_task_run(
    id: Value,
    store: BrownieStore,
    record: TaskRecord,
) -> JsonRpcResponse<Value> {
    if let Err(rejection) = revalidate_verification_recovery_retry_task_for_run(&store, &record) {
        return match rejection {
            TaskRunAdmissionRejection::InvalidParams(message) => {
                error_response(id, -32602, message)
            }
            TaskRunAdmissionRejection::Internal(message) => {
                error_response(id, -32603, &format!("internal error: {message}"))
            }
        };
    }

    match validate_task_run_admission(&record, &store) {
        Ok(TaskRunAdmission::Standard) => {}
        Ok(TaskRunAdmission::ParentJoinContinuation(_)) => {
            return error_response(
                id,
                -32602,
                "invalid params: verification recovery retry task cannot admit parent join continuation",
            )
        }
        Err(rejection) => {
            return match rejection {
                TaskRunAdmissionRejection::InvalidParams(message) => {
                    error_response(id, -32602, message)
                }
                TaskRunAdmissionRejection::Internal(message) => {
                    error_response(id, -32603, &format!("internal error: {message}"))
                }
            }
        }
    }

    let running = match store.tasks().update_task_status(
        &record.task_id,
        TaskStatus::Running,
        LedgerEventKind::TaskRunning,
    ) {
        Ok(record) => record,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };

    let policy = match resolve_policy_for_task_run(&running, &store) {
        Ok(policy) => policy,
        Err(message) => return error_response(id, -32603, &format!("internal error: {message}")),
    };
    if let Err(error) = append_permission_checks(&store, &running, &policy) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = append_tool_plan_events(&store, &running, &policy) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }
    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::AgentLoopStarted,
        Some(json!({
            "entrypoint": METHOD_TASK_RUN,
            "state": agent_loop_state_name(AgentLoopState::BuildingContext),
            "verification_recovery_retry": true,
        })),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }

    let Some(provenance) = running.verification_recovery_retry_provenance.as_ref() else {
        return error_response(
            id,
            -32603,
            "internal error: missing verification recovery retry provenance",
        );
    };
    for tool_id in &provenance.retried_verifier_tool_ids {
        if let Err(error) =
            append_verification_recovery_retry_tool_execution(&store, &running, &policy, tool_id)
        {
            return error_response(id, -32603, &format!("internal error: {error}"));
        }
    }

    let completion_gate_events = match store.tasks().read_ledger_events(&running.run_id) {
        Ok(events) => events,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let verification_completion_gate =
        verification_completion_gate_for_run(&completion_gate_events);
    let agent_loop_final_state = match verification_completion_gate.as_ref() {
        Some(gate) if gate.status == VERIFICATION_COMPLETION_GATE_STATUS_FAILED => {
            AgentLoopState::Failed
        }
        Some(_) => AgentLoopState::Completed,
        None => AgentLoopState::Failed,
    };
    let agent_loop_completion_summary = match verification_completion_gate.as_ref() {
        Some(gate) if gate.status == VERIFICATION_COMPLETION_GATE_STATUS_FAILED => {
            verification_completion_gate_failed_summary(gate)
        }
        Some(gate) => format!(
            "Verification recovery retry completed: required_verifier_count={} passed_verifier_count={}",
            gate.required_verifier_count, gate.passed_verifier_count
        ),
        None => "Verification recovery retry failed: missing verifier completion gate.".to_string(),
    };

    if let Err(error) = store.tasks().append_task_event_with_payload(
        &running,
        LedgerEventKind::AgentLoopCompleted,
        Some(json!({
            "final_state": agent_loop_state_name(agent_loop_final_state),
            "completion_summary": agent_loop_completion_summary.clone(),
            "completion_result_fingerprint": completion_result_fingerprint(
                agent_loop_final_state,
                &agent_loop_completion_summary,
                "",
            ),
            "verification_recovery_retry": true,
        })),
    ) {
        return error_response(id, -32603, &format!("internal error: {error}"));
    }

    let final_status = match agent_loop_final_state {
        AgentLoopState::Completed => TaskStatus::Completed,
        AgentLoopState::Cancelled => TaskStatus::Cancelled,
        _ => TaskStatus::Failed,
    };
    let event_kind = match final_status {
        TaskStatus::Completed => LedgerEventKind::TaskCompleted,
        TaskStatus::Cancelled => LedgerEventKind::TaskCancelled,
        _ => LedgerEventKind::TaskFailed,
    };
    let terminal_payload = verification_completion_gate
        .as_ref()
        .map(verification_completion_gate_payload);
    match store.tasks().update_task_status_with_payload(
        &running.task_id,
        final_status,
        event_kind,
        terminal_payload,
    ) {
        Ok(record) => {
            let verification_recovery_retry = match verification_recovery_retry_outcome_for_run(
                &store,
                &record,
                verification_completion_gate.as_ref(),
                false,
            ) {
                Ok(outcome) => outcome,
                Err(error) => {
                    return error_response(id, -32603, &format!("internal error: {error}"))
                }
            };
            result_response(
                id,
                json!(TaskRunResult {
                    task_id: record.task_id,
                    run_id: record.run_id,
                    status: record.status,
                    agent_loop: TaskRunAgentLoopSummary {
                        final_state: agent_loop_state_name(agent_loop_final_state).to_string(),
                        completion_summary: agent_loop_completion_summary,
                    },
                    verification_completion_gate,
                    verification_recovery_repair: None,
                    verification_recovery_retry,
                    recovery_cycle_budget_outcome: None,
                    child_orchestration_outcome: None,
                    parent_join_readiness_outcome: None,
                }),
            )
        }
        Err(error) => error_response(id, -32603, &format!("internal error: {error}")),
    }
}

fn append_sensitive_scan_event(
    store: &BrownieStore,
    running: &brownie_protocol::TaskRecord,
    scan: &PromptSensitiveScanResult,
    mode: &PromptSensitiveGuardMode,
    failed: bool,
) -> anyhow::Result<()> {
    if !failed && scan.findings.is_empty() {
        return Ok(());
    }
    let mut categories = scan
        .findings
        .iter()
        .map(|f| f.category.clone())
        .collect::<Vec<_>>();
    categories.sort();
    categories.dedup();
    let mut message_indexes = scan
        .findings
        .iter()
        .map(|f| f.message_index)
        .collect::<Vec<_>>();
    message_indexes.sort_unstable();
    message_indexes.dedup();
    store.tasks().append_task_event_with_payload(
        running,
        if failed {
            LedgerEventKind::PromptSensitiveScanFailed
        } else {
            LedgerEventKind::PromptSensitiveScanCompleted
        },
        Some(json!({
            "mode": mode.as_config_str(),
            "sensitive_guard": mode.as_config_str(),
            "finding_count": scan.findings.len(),
            "categories": categories,
            "message_indexes": message_indexes,
        })),
    )
}

#[derive(Debug)]
enum TaskRunAdmissionRejection {
    InvalidParams(&'static str),
    Internal(String),
}

enum TaskRunAdmission {
    Standard,
    ParentJoinContinuation(ParentJoinContinuationAdmission),
}

fn task_run_admission_rejection_message(error: TaskRunAdmissionRejection) -> String {
    match error {
        TaskRunAdmissionRejection::InvalidParams(message) => message.to_string(),
        TaskRunAdmissionRejection::Internal(message) => message,
    }
}

struct ParentJoinContinuationAdmission {
    child_completion_summaries: Vec<String>,
    child_completion_fingerprint: String,
    child_completion_fingerprint_input_count: usize,
    child_completion_child_count: usize,
    child_terminal_completed_count: usize,
    child_terminal_failed_count: usize,
    child_recovery_cycle_depth: usize,
}

impl TaskRunAdmission {
    fn child_completion_summaries(&self) -> Vec<String> {
        match self {
            Self::Standard => Vec::new(),
            Self::ParentJoinContinuation(admission) => admission.child_completion_summaries.clone(),
        }
    }

    fn parent_join_continuation_consumption(&self) -> Option<ParentJoinContinuationConsumption> {
        match self {
            Self::Standard => None,
            Self::ParentJoinContinuation(admission) => Some(ParentJoinContinuationConsumption {
                child_completion_fingerprint: admission.child_completion_fingerprint.clone(),
                child_completion_fingerprint_input_count: admission
                    .child_completion_fingerprint_input_count,
                child_completion_child_count: admission.child_completion_child_count,
                child_terminal_completed_count: admission.child_terminal_completed_count,
                child_terminal_failed_count: admission.child_terminal_failed_count,
                child_recovery_cycle_depth: admission.child_recovery_cycle_depth,
            }),
        }
    }

    fn parent_join_continuation_materialization(
        &self,
    ) -> Option<ParentJoinContinuationMaterialization> {
        match self {
            Self::Standard => None,
            Self::ParentJoinContinuation(admission) => {
                Some(ParentJoinContinuationMaterialization {
                    admission_id: String::new(),
                    child_completion_fingerprint: admission.child_completion_fingerprint.clone(),
                    child_completion_fingerprint_input_count: admission
                        .child_completion_fingerprint_input_count,
                    child_completion_child_count: admission.child_completion_child_count,
                    child_terminal_completed_count: admission.child_terminal_completed_count,
                    child_terminal_failed_count: admission.child_terminal_failed_count,
                    child_recovery_cycle_depth: admission.child_recovery_cycle_depth,
                })
            }
        }
    }
}

struct ParentJoinContinuationConsumption {
    child_completion_fingerprint: String,
    child_completion_fingerprint_input_count: usize,
    child_completion_child_count: usize,
    child_terminal_completed_count: usize,
    child_terminal_failed_count: usize,
    child_recovery_cycle_depth: usize,
}

#[derive(Clone)]
struct ParentJoinContinuationMaterialization {
    admission_id: String,
    child_completion_fingerprint: String,
    child_completion_fingerprint_input_count: usize,
    child_completion_child_count: usize,
    child_terminal_completed_count: usize,
    child_terminal_failed_count: usize,
    child_recovery_cycle_depth: usize,
}

fn validate_task_run_admission(
    record: &TaskRecord,
    store: &BrownieStore,
) -> Result<TaskRunAdmission, TaskRunAdmissionRejection> {
    match record.status {
        TaskStatus::Created => Ok(TaskRunAdmission::Standard),
        TaskStatus::Queued => {
            validate_controlled_queued_child_task_provenance(record, store)?;
            Ok(TaskRunAdmission::Standard)
        }
        TaskStatus::Completed => Ok(TaskRunAdmission::ParentJoinContinuation(
            validate_completed_parent_join_continuation_admission(record, store)?,
        )),
        TaskStatus::Running | TaskStatus::Failed | TaskStatus::Cancelled => {
            Err(TaskRunAdmissionRejection::InvalidParams(
                "invalid params: task must be Created, a controlled Queued child task, or a completed parent with completed controlled child tasks or failed controlled child tasks",
            ))
        }
    }
}

fn validate_completed_parent_join_continuation_admission(
    record: &TaskRecord,
    store: &BrownieStore,
) -> Result<ParentJoinContinuationAdmission, TaskRunAdmissionRejection> {
    if record.parent_run_id.is_some() {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: completed child task cannot be rerun",
        ));
    }

    let mut child_tasks = store
        .tasks()
        .list_tasks()
        .map_err(|error| TaskRunAdmissionRejection::Internal(error.to_string()))?
        .into_iter()
        .filter(|task| task.parent_run_id.as_deref() == Some(record.run_id.as_str()))
        .collect::<Vec<_>>();
    child_tasks.sort_by(|a, b| {
        a.source_candidate_id
            .cmp(&b.source_candidate_id)
            .then(a.task_id.cmp(&b.task_id))
    });

    if child_tasks.is_empty() {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: parent join continuation requires completed controlled child tasks or failed controlled child tasks",
        ));
    }

    for child in &child_tasks {
        validate_controlled_queued_child_task_provenance(child, store)?;
        if !matches!(child.status, TaskStatus::Completed | TaskStatus::Failed) {
            return Err(TaskRunAdmissionRejection::InvalidParams(
                "invalid params: parent join continuation requires completed controlled child tasks or failed controlled child tasks",
            ));
        }
        if !child_has_terminal_parent_join_outcome(store, child)? {
            return Err(TaskRunAdmissionRejection::InvalidParams(
                "invalid params: parent join continuation requires completed controlled child tasks or failed controlled child tasks",
            ));
        }
    }

    let child_evidence = child_tasks
        .iter()
        .map(|child| parent_join_child_completion_evidence(store, child))
        .collect::<Result<Vec<_>, _>>()?;
    let child_terminal_completed_count = child_tasks
        .iter()
        .filter(|child| child.status == TaskStatus::Completed)
        .count();
    let child_terminal_failed_count = child_tasks
        .iter()
        .filter(|child| child.status == TaskStatus::Failed)
        .count();
    let child_recovery_cycle_depth = if child_terminal_failed_count > 0 {
        child_terminal_completed_count
    } else {
        0
    };
    let (child_completion_fingerprint, child_completion_fingerprint_input_count) =
        parent_join_child_completion_fingerprint(&child_evidence);
    if parent_join_child_completion_fingerprint_consumed(
        store,
        record,
        &child_completion_fingerprint,
    )? {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: parent join continuation for this completed child result set has already been consumed",
        ));
    }

    let mut summaries = child_evidence
        .iter()
        .take(MAX_PARENT_JOIN_CHILD_CONTEXT_SUMMARIES)
        .map(|evidence| evidence.summary.clone())
        .collect::<Vec<_>>();
    if child_tasks.len() > MAX_PARENT_JOIN_CHILD_CONTEXT_SUMMARIES {
        summaries.push(format!(
            "terminal_child_summary_omitted count={}",
            child_tasks.len() - MAX_PARENT_JOIN_CHILD_CONTEXT_SUMMARIES
        ));
    }
    Ok(ParentJoinContinuationAdmission {
        child_completion_summaries: summaries,
        child_completion_fingerprint,
        child_completion_fingerprint_input_count,
        child_completion_child_count: child_tasks.len(),
        child_terminal_completed_count,
        child_terminal_failed_count,
        child_recovery_cycle_depth,
    })
}

fn child_has_terminal_parent_join_outcome(
    store: &BrownieStore,
    child: &TaskRecord,
) -> Result<bool, TaskRunAdmissionRejection> {
    let events = store
        .tasks()
        .read_ledger_events(&child.run_id)
        .map_err(|error| TaskRunAdmissionRejection::Internal(error.to_string()))?;
    match child.status {
        TaskStatus::Completed => {
            let has_completed_agent_loop = events.iter().rev().any(|event| {
                event.kind == LedgerEventKind::AgentLoopCompleted
                    && event
                        .payload
                        .as_ref()
                        .and_then(|payload| payload.get("final_state"))
                        .and_then(Value::as_str)
                        == Some("Completed")
            });
            let has_task_completed = events
                .iter()
                .any(|event| event.kind == LedgerEventKind::TaskCompleted);
            Ok(has_completed_agent_loop && has_task_completed)
        }
        TaskStatus::Failed => {
            let has_task_failed = events
                .iter()
                .any(|event| event.kind == LedgerEventKind::TaskFailed);
            let has_failed_agent_loop = events.iter().rev().any(|event| {
                event.kind == LedgerEventKind::AgentLoopCompleted
                    && event
                        .payload
                        .as_ref()
                        .and_then(|payload| payload.get("final_state"))
                        .and_then(Value::as_str)
                        == Some("Failed")
            });
            let has_redacted_failure_event = events.iter().any(|event| {
                matches!(
                    event.kind,
                    LedgerEventKind::LlmRequestFailed | LedgerEventKind::SecondPassLlmRequestFailed
                )
            });
            Ok(has_task_failed && (has_failed_agent_loop || has_redacted_failure_event))
        }
        TaskStatus::Created | TaskStatus::Queued | TaskStatus::Running | TaskStatus::Cancelled => {
            Ok(false)
        }
    }
}

struct ParentJoinChildCompletionEvidence {
    summary: String,
    fingerprint_inputs: Vec<String>,
}

fn parent_join_child_completion_evidence(
    store: &BrownieStore,
    child: &TaskRecord,
) -> Result<ParentJoinChildCompletionEvidence, TaskRunAdmissionRejection> {
    let events = store
        .tasks()
        .read_ledger_events(&child.run_id)
        .map_err(|error| TaskRunAdmissionRejection::Internal(error.to_string()))?;
    let summary =
        child_task_inspect_summary(store, child).map_err(TaskRunAdmissionRejection::Internal)?;
    let source_candidate_id = summary.source_candidate_id.as_deref().unwrap_or("<none>");
    let source_handoff_envelope_id = summary
        .source_handoff_envelope_id
        .as_deref()
        .unwrap_or("<none>");
    let source_handoff_envelope_fingerprint = summary
        .source_handoff_envelope_fingerprint
        .as_deref()
        .unwrap_or("<none>");
    let parent_task_id = summary.parent_task_id.as_deref().unwrap_or("<none>");
    let parent_run_id = summary.parent_run_id.as_deref().unwrap_or("<none>");
    let status = format!("{:?}", summary.status);
    let terminal_outcome_kind = match summary.status {
        TaskStatus::Completed => "completed_child",
        TaskStatus::Failed => "failed_child",
        TaskStatus::Created | TaskStatus::Queued | TaskStatus::Running | TaskStatus::Cancelled => {
            "nonterminal_child"
        }
    };
    let (terminal_final_state, terminal_result_fingerprint, summary_text) = match summary.status {
        TaskStatus::Completed => {
            let completion_final_state = summary
                .completion_final_state
                .as_deref()
                .unwrap_or("<none>")
                .to_string();
            let completion_result_fingerprint = summary
                .completion_result_fingerprint
                .as_deref()
                .unwrap_or("<none>")
                .to_string();
            let summary_text = format!(
                "completed_child task_id={} run_id={} status={:?} source_candidate_id={} source_handoff_envelope_fingerprint={} completion_final_state={} completion_result_fingerprint={} completion_summary_preview={} final_response_preview={}",
                summary.task_id,
                summary.run_id,
                summary.status,
                summary
                    .source_candidate_id
                    .as_deref()
                    .unwrap_or("<none>"),
                summary
                    .source_handoff_envelope_fingerprint
                    .as_deref()
                    .unwrap_or("<none>"),
                completion_final_state,
                completion_result_fingerprint,
                summary
                    .completion_summary_preview
                    .as_deref()
                    .unwrap_or("<none>"),
                summary
                    .final_response_preview
                    .as_deref()
                    .unwrap_or("<none>")
            );
            (
                completion_final_state,
                completion_result_fingerprint,
                summary_text,
            )
        }
        TaskStatus::Failed => {
            let failure_final_state = summary
                .completion_final_state
                .as_deref()
                .filter(|state| *state == "Failed")
                .unwrap_or("Failed")
                .to_string();
            let failure_result_fingerprint = child_failure_result_fingerprint(
                &events,
                summary.completion_result_fingerprint.as_deref(),
            );
            let failure_summary_preview = child_failure_summary_preview(&events)
                .unwrap_or_else(|| "failed_child_summary_unavailable".to_string());
            let summary_text = format!(
                "failed_child task_id={} run_id={} status={:?} source_candidate_id={} source_handoff_envelope_fingerprint={} failure_final_state={} failure_result_fingerprint={} failure_summary_preview={} final_response_preview={}",
                summary.task_id,
                summary.run_id,
                summary.status,
                summary
                    .source_candidate_id
                    .as_deref()
                    .unwrap_or("<none>"),
                summary
                    .source_handoff_envelope_fingerprint
                    .as_deref()
                    .unwrap_or("<none>"),
                failure_final_state,
                failure_result_fingerprint,
                failure_summary_preview,
                summary
                    .final_response_preview
                    .as_deref()
                    .unwrap_or("<none>")
            );
            (
                failure_final_state,
                failure_result_fingerprint,
                summary_text,
            )
        }
        TaskStatus::Created | TaskStatus::Queued | TaskStatus::Running | TaskStatus::Cancelled => (
            "<none>".to_string(),
            "<none>".to_string(),
            format!(
                "nonterminal_child task_id={} run_id={} status={:?}",
                summary.task_id, summary.run_id, summary.status
            ),
        ),
    };
    Ok(ParentJoinChildCompletionEvidence {
        summary: summary_text,
        fingerprint_inputs: vec![
            format!("task_id={}", summary.task_id),
            format!("run_id={}", summary.run_id),
            format!("status={status}"),
            format!("terminal_outcome_kind={terminal_outcome_kind}"),
            format!("parent_task_id={parent_task_id}"),
            format!("parent_run_id={parent_run_id}"),
            format!("source_candidate_id={source_candidate_id}"),
            format!("source_handoff_envelope_id={source_handoff_envelope_id}"),
            format!("source_handoff_envelope_fingerprint={source_handoff_envelope_fingerprint}"),
            format!("terminal_final_state={terminal_final_state}"),
            format!("terminal_result_fingerprint={terminal_result_fingerprint}"),
        ],
    })
}

fn child_failure_summary_preview(events: &[LedgerEvent]) -> Option<String> {
    events
        .iter()
        .rev()
        .find(|event| {
            matches!(
                event.kind,
                LedgerEventKind::LlmRequestFailed | LedgerEventKind::SecondPassLlmRequestFailed
            )
        })
        .and_then(|event| event.payload.as_ref())
        .and_then(|payload| payload.get("reason"))
        .and_then(Value::as_str)
        .map(redact_secret)
        .map(|reason| preview_with_limit(&reason, CHILD_FAILURE_SUMMARY_PREVIEW_CHARS))
}

fn child_failure_result_fingerprint(
    events: &[LedgerEvent],
    completion_result_fingerprint: Option<&str>,
) -> String {
    if let Some(fingerprint) =
        completion_result_fingerprint.filter(|fingerprint| fingerprint.starts_with("sha256:"))
    {
        return fingerprint.to_string();
    }

    let failure_event = events.iter().rev().find(|event| {
        matches!(
            event.kind,
            LedgerEventKind::LlmRequestFailed | LedgerEventKind::SecondPassLlmRequestFailed
        )
    });
    let payload = failure_event.and_then(|event| event.payload.as_ref());
    let reason = payload
        .and_then(|payload| payload.get("reason"))
        .and_then(Value::as_str)
        .map(redact_secret)
        .unwrap_or_else(|| "failed_child_reason_unavailable".to_string());
    let reason_sha256 = payload
        .and_then(|payload| payload.get("reason_sha256"))
        .and_then(Value::as_str)
        .filter(|fingerprint| fingerprint.starts_with("sha256:"))
        .map(ToString::to_string)
        .unwrap_or_else(|| format!("sha256:{}", hex_sha256(reason.as_bytes())));
    let reason_chars = payload
        .and_then(|payload| payload.get("reason_chars"))
        .and_then(Value::as_u64)
        .unwrap_or_else(|| reason.chars().count() as u64);
    let provider = payload
        .and_then(|payload| payload.get("provider"))
        .and_then(Value::as_str)
        .unwrap_or("<none>");
    let model = payload
        .and_then(|payload| payload.get("model"))
        .and_then(Value::as_str)
        .unwrap_or("<none>");
    let failure_event_kind = failure_event
        .map(|event| format!("{:?}", event.kind))
        .unwrap_or_else(|| "TaskFailed".to_string());
    let canonical = json!({
        "version": "child_failure_result_fingerprint_v1",
        "terminal_status": "Failed",
        "failure_event_kind": failure_event_kind,
        "provider": provider,
        "model": model,
        "reason_chars": reason_chars,
        "reason_sha256": reason_sha256,
    });
    format!("sha256:{}", hex_sha256(canonical.to_string().as_bytes()))
}

fn parent_join_child_completion_fingerprint(
    child_evidence: &[ParentJoinChildCompletionEvidence],
) -> (String, usize) {
    let mut inputs = vec![
        "parent_join_child_completion_fingerprint_v3_terminal_outcome".to_string(),
        format!("child_count={}", child_evidence.len()),
    ];
    for evidence in child_evidence {
        inputs.extend(evidence.fingerprint_inputs.iter().cloned());
    }
    let input_count = inputs.len();
    (
        format!("sha256:{}", hex_sha256(inputs.join("\n").as_bytes())),
        input_count,
    )
}

fn parent_join_child_completion_fingerprint_consumed(
    store: &BrownieStore,
    record: &TaskRecord,
    child_completion_fingerprint: &str,
) -> Result<bool, TaskRunAdmissionRejection> {
    let events = store
        .tasks()
        .read_ledger_events(&record.run_id)
        .map_err(|error| TaskRunAdmissionRejection::Internal(error.to_string()))?;
    Ok(events.iter().any(|event| {
        if event.kind != LedgerEventKind::ParentJoinContinuationFingerprintConsumed {
            return false;
        }
        let Some(payload) = event.payload.as_ref() else {
            return false;
        };
        if payload
            .get("child_completion_fingerprint")
            .and_then(Value::as_str)
            != Some(child_completion_fingerprint)
        {
            return false;
        }
        let Some(admission_id) = payload.get("admission_id").and_then(Value::as_str) else {
            return true;
        };
        let Some(running_index) = events.iter().position(|candidate| {
            candidate.kind == LedgerEventKind::TaskRunning
                && candidate
                    .payload
                    .as_ref()
                    .and_then(|payload| payload.get("admission_id"))
                    .and_then(Value::as_str)
                    == Some(admission_id)
        }) else {
            return false;
        };
        for candidate in events.iter().skip(running_index + 1) {
            if candidate.kind == LedgerEventKind::ParentJoinContinuationFingerprintConsumed {
                return false;
            }
            if matches!(
                candidate.kind,
                LedgerEventKind::TaskCompleted
                    | LedgerEventKind::TaskFailed
                    | LedgerEventKind::TaskCancelled
            ) {
                return true;
            }
        }
        false
    }))
}

fn validate_controlled_queued_child_task_provenance(
    record: &TaskRecord,
    store: &BrownieStore,
) -> Result<(), TaskRunAdmissionRejection> {
    let parent_task_id = required_task_run_provenance(record.parent_task_id.as_deref())?;
    let parent_run_id = required_task_run_provenance(record.parent_run_id.as_deref())?;
    let source_candidate_id = required_task_run_provenance(record.source_candidate_id.as_deref())?;
    let source_handoff_envelope_id =
        required_task_run_provenance(record.source_handoff_envelope_id.as_deref())?;
    let source_handoff_envelope_fingerprint =
        required_task_run_provenance(record.source_handoff_envelope_fingerprint.as_deref())?;

    let parent = store
        .tasks()
        .get_task(parent_task_id)
        .map_err(|error| TaskRunAdmissionRejection::Internal(error.to_string()))?
        .ok_or(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: queued child task parent provenance is invalid",
        ))?;
    if parent.run_id != parent_run_id {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: queued child task parent provenance is invalid",
        ));
    }

    let parent_events = store
        .tasks()
        .read_ledger_events(parent_run_id)
        .map_err(|error| TaskRunAdmissionRejection::Internal(error.to_string()))?;
    let covered_by_handoff_envelope = parent_events.iter().any(|event| {
        if event.kind != LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded {
            return false;
        }
        let Some(payload) = event.payload.as_ref() else {
            return false;
        };
        payload.get("handoff_envelope_id").and_then(Value::as_str)
            == Some(source_handoff_envelope_id)
            && payload
                .get("handoff_envelope_fingerprint")
                .and_then(Value::as_str)
                == Some(source_handoff_envelope_fingerprint)
            && (payload_string_array(payload, "candidate_ids")
                .iter()
                .any(|candidate| candidate == source_candidate_id)
                || payload_string_array(payload, "blocked_candidate_ids")
                    .iter()
                    .any(|candidate| candidate == source_candidate_id))
    });
    if !covered_by_handoff_envelope {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: queued child task source provenance is invalid",
        ));
    }
    validate_recovery_cycle_child_run_provenance(
        record,
        &parent_events,
        source_handoff_envelope_id,
        source_handoff_envelope_fingerprint,
    )?;

    Ok(())
}

fn validate_recovery_cycle_child_run_provenance(
    record: &TaskRecord,
    parent_events: &[LedgerEvent],
    source_handoff_envelope_id: &str,
    source_handoff_envelope_fingerprint: &str,
) -> Result<(), TaskRunAdmissionRejection> {
    let Some(provenance) = record.recovery_cycle_provenance.as_ref() else {
        if source_handoff_envelope_requires_recovery_cycle_provenance(
            parent_events,
            source_handoff_envelope_id,
            source_handoff_envelope_fingerprint,
        ) {
            return Err(TaskRunAdmissionRejection::InvalidParams(
                "invalid params: recovery-cycle child task provenance is missing",
            ));
        }
        return Ok(());
    };
    if !recovery_cycle_child_provenance_is_internally_valid(provenance) {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: recovery-cycle child task provenance is invalid",
        ));
    }
    if recovery_cycle_depth_exceeds_budget(provenance.parent_join_recovery_cycle_depth) {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: recovery-cycle child task provenance exceeds runtime budget",
        ));
    }

    if !parent_events
        .iter()
        .any(|event| recovery_cycle_provenance_matches_parent_join(event, provenance))
    {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: recovery-cycle child task provenance does not match parent join admission",
        ));
    }

    if !parent_events.iter().any(|event| {
        recovery_cycle_provenance_matches_handoff_envelope(
            event,
            provenance,
            source_handoff_envelope_id,
            source_handoff_envelope_fingerprint,
        )
    }) {
        return Err(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: recovery-cycle child task provenance does not match parent handoff envelope",
        ));
    }

    Ok(())
}

fn recovery_cycle_depth_exceeds_budget(depth: usize) -> bool {
    depth > MAX_RECOVERY_CYCLE_DEPTH
}

fn source_handoff_envelope_requires_recovery_cycle_provenance(
    parent_events: &[LedgerEvent],
    source_handoff_envelope_id: &str,
    source_handoff_envelope_fingerprint: &str,
) -> bool {
    parent_events.iter().any(|event| {
        if event.kind != LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded {
            return false;
        }
        let Some(payload) = event.payload.as_ref() else {
            return false;
        };
        payload
            .get("handoff_envelope_status")
            .and_then(Value::as_str)
            == Some("Accepted")
            && payload.get("handoff_envelope_id").and_then(Value::as_str)
                == Some(source_handoff_envelope_id)
            && payload
                .get("handoff_envelope_fingerprint")
                .and_then(Value::as_str)
                == Some(source_handoff_envelope_fingerprint)
            && payload
                .get("parent_join_recovery_cycle")
                .and_then(Value::as_bool)
                == Some(true)
    })
}

fn recovery_cycle_child_provenance_is_internally_valid(
    provenance: &RecoveryCycleChildProvenance,
) -> bool {
    !provenance.parent_join_admission_id.trim().is_empty()
        && is_sha256_fingerprint(&provenance.parent_join_child_completion_fingerprint)
        && provenance
            .parent_join_terminal_failed_child_count
            .checked_add(provenance.parent_join_terminal_completed_child_count)
            == Some(provenance.parent_join_child_completion_child_count)
        && provenance.parent_join_recovery_cycle
        && provenance.parent_join_recovery_cycle_depth >= 1
}

fn recovery_cycle_provenance_matches_parent_join(
    event: &LedgerEvent,
    provenance: &RecoveryCycleChildProvenance,
) -> bool {
    if event.kind != LedgerEventKind::ParentJoinContinuationFingerprintConsumed {
        return false;
    }
    let Some(payload) = event.payload.as_ref() else {
        return false;
    };
    payload.get("admission_id").and_then(Value::as_str)
        == Some(provenance.parent_join_admission_id.as_str())
        && payload
            .get("child_completion_fingerprint")
            .and_then(Value::as_str)
            == Some(provenance.parent_join_child_completion_fingerprint.as_str())
        && payload_usize_eq(
            payload,
            "child_completion_child_count",
            provenance.parent_join_child_completion_child_count,
        )
        && payload_usize_eq(
            payload,
            "child_terminal_failed_count",
            provenance.parent_join_terminal_failed_child_count,
        )
        && payload_usize_eq(
            payload,
            "child_terminal_completed_count",
            provenance.parent_join_terminal_completed_child_count,
        )
        && payload_usize_eq(
            payload,
            "child_recovery_cycle_depth",
            provenance.parent_join_recovery_cycle_depth,
        )
}

fn recovery_cycle_provenance_matches_handoff_envelope(
    event: &LedgerEvent,
    provenance: &RecoveryCycleChildProvenance,
    source_handoff_envelope_id: &str,
    source_handoff_envelope_fingerprint: &str,
) -> bool {
    if event.kind != LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded {
        return false;
    }
    let Some(payload) = event.payload.as_ref() else {
        return false;
    };
    payload
        .get("handoff_envelope_status")
        .and_then(Value::as_str)
        == Some("Accepted")
        && payload.get("handoff_envelope_id").and_then(Value::as_str)
            == Some(source_handoff_envelope_id)
        && payload
            .get("handoff_envelope_fingerprint")
            .and_then(Value::as_str)
            == Some(source_handoff_envelope_fingerprint)
        && payload
            .get("parent_join_admission_id")
            .and_then(Value::as_str)
            == Some(provenance.parent_join_admission_id.as_str())
        && payload
            .get("parent_join_child_completion_fingerprint")
            .and_then(Value::as_str)
            == Some(provenance.parent_join_child_completion_fingerprint.as_str())
        && payload_usize_eq(
            payload,
            "parent_join_child_completion_child_count",
            provenance.parent_join_child_completion_child_count,
        )
        && payload_usize_eq(
            payload,
            "parent_join_terminal_failed_child_count",
            provenance.parent_join_terminal_failed_child_count,
        )
        && payload_usize_eq(
            payload,
            "parent_join_terminal_completed_child_count",
            provenance.parent_join_terminal_completed_child_count,
        )
        && payload
            .get("parent_join_recovery_cycle")
            .and_then(Value::as_bool)
            == Some(provenance.parent_join_recovery_cycle)
        && payload_usize_eq(
            payload,
            "parent_join_recovery_cycle_depth",
            provenance.parent_join_recovery_cycle_depth,
        )
}

fn payload_usize_eq(payload: &Value, key: &str, expected: usize) -> bool {
    payload
        .get(key)
        .and_then(Value::as_u64)
        .and_then(|value| usize::try_from(value).ok())
        == Some(expected)
}

fn required_task_run_provenance(value: Option<&str>) -> Result<&str, TaskRunAdmissionRejection> {
    value
        .filter(|value| !value.trim().is_empty())
        .ok_or(TaskRunAdmissionRejection::InvalidParams(
            "invalid params: queued child task must include complete parent/source provenance",
        ))
}

fn fail_llm_request(
    store: &BrownieStore,
    running: &brownie_protocol::TaskRecord,
    id: Value,
    selection: RuntimeLlmProviderStatus,
    reason: &str,
    kind: LedgerEventKind,
) -> JsonRpcResponse<Value> {
    let redacted_reason = redact_secret(reason);
    let reason_preview = preview_with_limit(&redacted_reason, LLM_FAILURE_REASON_PREVIEW_CHARS);
    let reason_chars = redacted_reason.chars().count();
    let reason_sha256 = format!("sha256:{}", hex_sha256(redacted_reason.as_bytes()));
    if redacted_reason.contains("Prompt sensitive-content guard failed") {
        let _ = store.tasks().append_task_event_with_payload(
            running,
            LedgerEventKind::PromptSensitiveScanFailed,
            Some(json!({
                "mode": selection.sensitive_guard_mode.as_config_str(),
                "sensitive_guard": selection.sensitive_guard_mode.as_config_str(),
                "finding_count": 1,
                "categories": [],
                "message_indexes": [],
            })),
        );
    }
    let _ = store.tasks().append_task_event_with_payload(
        running,
        kind,
        Some(json!({
            "provider": provider_kind_name(&selection.status.provider),
            "model": selection.status.model,
            "reason": reason_preview.clone(),
            "reason_chars": reason_chars,
            "reason_sha256": reason_sha256,
            "reason_truncated": reason_chars > LLM_FAILURE_REASON_PREVIEW_CHARS,
            "base_url": selection.status.base_url.as_deref().map(redact_secret),
            "strict": selection.strict,
            "sensitive_guard": selection.sensitive_guard_mode.as_config_str(),
        })),
    );
    let updated_record = store.tasks().update_task_status(
        &running.task_id,
        TaskStatus::Failed,
        LedgerEventKind::TaskFailed,
    );
    if let Ok(record) = updated_record {
        match parent_join_readiness_outcome_for_terminal_child(store, &record) {
            Ok(Some(parent_join_readiness_outcome)) => {
                return result_response(
                    id,
                    json!(TaskRunResult {
                        task_id: record.task_id,
                        run_id: record.run_id,
                        status: record.status,
                        agent_loop: controlled_child_failed_agent_loop_summary(),
                        verification_completion_gate: None,
                        verification_recovery_repair: None,
                        verification_recovery_retry: None,
                        recovery_cycle_budget_outcome: None,
                        child_orchestration_outcome: None,
                        parent_join_readiness_outcome: Some(parent_join_readiness_outcome),
                    }),
                );
            }
            Ok(None) => {}
            Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
        }
    }
    error_response(
        id,
        -32603,
        &format!("internal error: LLM request failed: {}", reason_preview),
    )
}

fn handle_run_events(id: Value, params: Option<Value>) -> JsonRpcResponse<Value> {
    let params: RunEventsParams = match parse_params(params) {
        Ok(params) => params,
        Err(message) => return error_response(id, -32602, &message),
    };
    if params.run_id.trim().is_empty() {
        return error_response(id, -32602, "invalid params: run_id must not be empty");
    }
    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let events = match read_existing_run_events(&store, &params.run_id) {
        Ok(events) => events,
        Err(message) => return error_response(id, -32602, &message),
    };
    result_response(
        id,
        json!(RunEventsResult {
            run_id: params.run_id,
            events: events.into_iter().map(ledger_event_summary).collect(),
        }),
    )
}

