fn handle_task_inspect(id: Value, params: Option<Value>) -> JsonRpcResponse<Value> {
    let params: TaskInspectParams = match parse_params(params) {
        Ok(params) => params,
        Err(message) => return error_response(id, -32602, &message),
    };
    if params.task_id.trim().is_empty() {
        return error_response(id, -32602, "invalid params: task_id must not be empty");
    }
    let store = match BrownieStore::from_env_or_cwd() {
        Ok(store) => store,
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let task = match store.tasks().get_task(&params.task_id) {
        Ok(Some(record)) => record,
        Ok(None) => return error_response(id, -32602, "invalid params: task not found"),
        Err(error) => return error_response(id, -32603, &format!("internal error: {error}")),
    };
    let parent_join_readiness_summary =
        match parent_join_readiness_summary_for_child_inspection(&store, &task) {
            Ok(summary) => summary,
            Err(message) => {
                return error_response(id, -32603, &format!("internal error: {message}"))
            }
        };
    let consumed_parent_join_recovery_summary =
        match consumed_parent_join_recovery_summary_for_child_inspection(&store, &task) {
            Ok(summary) => summary,
            Err(message) => {
                return error_response(id, -32603, &format!("internal error: {message}"))
            }
        };
    match inspect_run(&store, &task.run_id) {
        Ok(run) => result_response(
            id,
            json!(TaskInspectResult {
                task,
                run,
                parent_join_readiness_summary,
                consumed_parent_join_recovery_summary
            }),
        ),
        Err(message) => error_response(id, -32602, &message),
    }
}

