#[derive(Clone)]
struct ConsumedParentJoinFingerprint {
    admission_id: String,
    child_completion_fingerprint: String,
    child_completion_child_count: usize,
    child_terminal_completed_count: usize,
    child_terminal_failed_count: usize,
    child_recovery_cycle_depth: usize,
}

fn consumed_parent_join_recovery_summary_for_child_inspection(
    store: &BrownieStore,
    record: &TaskRecord,
) -> Result<Option<ChildInspectConsumedParentJoinRecoverySummary>, String> {
    if !task_has_complete_controlled_child_provenance(record) {
        return Ok(None);
    }
    let Some(parent_task_id) = non_empty_record_string(record.parent_task_id.as_deref()) else {
        return Ok(None);
    };
    let Some(parent_run_id) = non_empty_record_string(record.parent_run_id.as_deref()) else {
        return Ok(None);
    };
    let Some(parent_record) = store
        .tasks()
        .get_task(&parent_task_id)
        .map_err(|error| format!("invalid params: {error}"))?
    else {
        return Ok(None);
    };
    if parent_record.run_id != parent_run_id
        || parent_record.parent_run_id.is_some()
        || parent_record.status != TaskStatus::Completed
    {
        return Ok(None);
    }

    let parent_events = store
        .tasks()
        .read_ledger_events(&parent_run_id)
        .map_err(|error| error.to_string())?;
    let mut controlled_children = controlled_child_records_for_parent_run(
        store,
        Some(&parent_task_id),
        &parent_run_id,
        None,
    )?;
    if !controlled_children
        .iter()
        .any(|child| child.task_id == record.task_id)
    {
        controlled_children.push(record.clone());
        sort_controlled_child_records(&mut controlled_children);
    }

    for event in parent_events.iter().rev() {
        let Some(consumption) = consumed_parent_join_fingerprint_from_event(event) else {
            continue;
        };
        if !parent_join_consumption_has_terminal_result(&parent_events, &consumption) {
            continue;
        }
        let inspected_is_continuation_child =
            child_recovery_provenance_matches_consumed_parent_join(record, &consumption)
                || child_handoff_fingerprint_matches_consumed_parent_join(
                    &parent_events,
                    record,
                    &consumption,
                );
        let inspected_is_consumed_terminal_child =
            consumed_terminal_controlled_child_set_contains_inspected_child(
                store,
                &parent_events,
                &controlled_children,
                &consumption,
                &record.task_id,
            )?;
        if !inspected_is_continuation_child && !inspected_is_consumed_terminal_child {
            continue;
        }

        let continuation_children = continuation_controlled_children_for_consumed_parent_join(
            &parent_events,
            &controlled_children,
            &consumption,
        );
        let continuation_runnable_child_task_ids = continuation_children
            .iter()
            .filter(|child| is_parent_join_runnable_pending_child_status(&child.status))
            .map(|child| child.task_id.clone())
            .collect::<Vec<_>>();
        let continuation_runnable_child_count = continuation_runnable_child_task_ids.len();
        let continuation_non_runnable_child_task_ids = continuation_children
            .iter()
            .filter(|child| is_parent_join_non_runnable_child_status(&child.status))
            .map(|child| child.task_id.clone())
            .collect::<Vec<_>>();
        let continuation_non_runnable_child_count = continuation_non_runnable_child_task_ids.len();
        let continuation_terminal_child_count = continuation_children
            .iter()
            .filter(|child| is_parent_join_terminal_child_status(&child.status))
            .count();
        let next_action = if continuation_non_runnable_child_count > 0 {
            "inspect_non_runnable_continuation_child_tasks"
        } else if continuation_runnable_child_count > 0 {
            "run_continuation_child_tasks_explicitly"
        } else {
            "inspect_parent_task"
        };

        return Ok(Some(ChildInspectConsumedParentJoinRecoverySummary {
            parent_task_id,
            parent_run_id,
            inspected_child_task_id: record.task_id.clone(),
            inspected_child_run_id: record.run_id.clone(),
            inspected_child_status: record.status.clone(),
            parent_join_consumed: true,
            consumed_terminal_controlled_child_count: consumption.child_completion_child_count,
            continuation_controlled_child_count: continuation_children.len(),
            continuation_runnable_child_count,
            continuation_runnable_child_task_ids,
            continuation_non_runnable_child_count,
            continuation_non_runnable_child_task_ids,
            continuation_terminal_child_count,
            parent_running_enabled: false,
            next_action: next_action.to_string(),
        }));
    }

    Ok(None)
}

fn consumed_parent_join_fingerprint_from_event(
    event: &LedgerEvent,
) -> Option<ConsumedParentJoinFingerprint> {
    if event.kind != LedgerEventKind::ParentJoinContinuationFingerprintConsumed {
        return None;
    }
    let payload = event.payload.as_ref()?;
    let admission_id = non_empty_payload_string(payload, "admission_id")?;
    let child_completion_fingerprint =
        non_empty_payload_string(payload, "child_completion_fingerprint")?;
    if !is_sha256_fingerprint(&child_completion_fingerprint) {
        return None;
    }
    Some(ConsumedParentJoinFingerprint {
        admission_id,
        child_completion_fingerprint,
        child_completion_child_count: payload_usize(payload, "child_completion_child_count")?,
        child_terminal_completed_count: payload_usize(payload, "child_terminal_completed_count")?,
        child_terminal_failed_count: payload_usize(payload, "child_terminal_failed_count")?,
        child_recovery_cycle_depth: payload_usize(payload, "child_recovery_cycle_depth")?,
    })
}

fn parent_join_consumption_has_terminal_result(
    parent_events: &[LedgerEvent],
    consumption: &ConsumedParentJoinFingerprint,
) -> bool {
    let Some(running_index) = parent_events.iter().position(|candidate| {
        candidate.kind == LedgerEventKind::TaskRunning
            && candidate
                .payload
                .as_ref()
                .and_then(|payload| payload.get("admission_id"))
                .and_then(Value::as_str)
                == Some(consumption.admission_id.as_str())
    }) else {
        return false;
    };
    parent_events
        .iter()
        .skip(running_index + 1)
        .take_while(|candidate| {
            candidate.kind != LedgerEventKind::ParentJoinContinuationFingerprintConsumed
        })
        .any(|candidate| {
            matches!(
                candidate.kind,
                LedgerEventKind::TaskCompleted
                    | LedgerEventKind::TaskFailed
                    | LedgerEventKind::TaskCancelled
            )
        })
}

fn child_recovery_provenance_matches_consumed_parent_join(
    child: &TaskRecord,
    consumption: &ConsumedParentJoinFingerprint,
) -> bool {
    let Some(provenance) = child.recovery_cycle_provenance.as_ref() else {
        return false;
    };
    recovery_cycle_child_provenance_is_internally_valid(provenance)
        && provenance.parent_join_admission_id == consumption.admission_id
        && provenance.parent_join_child_completion_fingerprint
            == consumption.child_completion_fingerprint
        && provenance.parent_join_child_completion_child_count
            == consumption.child_completion_child_count
        && provenance.parent_join_terminal_completed_child_count
            == consumption.child_terminal_completed_count
        && provenance.parent_join_terminal_failed_child_count
            == consumption.child_terminal_failed_count
        && provenance.parent_join_recovery_cycle_depth == consumption.child_recovery_cycle_depth
}

fn child_handoff_fingerprint_matches_consumed_parent_join(
    parent_events: &[LedgerEvent],
    child: &TaskRecord,
    consumption: &ConsumedParentJoinFingerprint,
) -> bool {
    let Some(fingerprint) = child.source_handoff_envelope_fingerprint.as_ref() else {
        return false;
    };
    consumed_parent_join_continuation_handoff_fingerprints(parent_events, consumption)
        .contains(fingerprint)
}

fn consumed_terminal_controlled_child_set_contains_inspected_child(
    store: &BrownieStore,
    parent_events: &[LedgerEvent],
    controlled_children: &[TaskRecord],
    consumption: &ConsumedParentJoinFingerprint,
    inspected_child_task_id: &str,
) -> Result<bool, String> {
    Ok(
        consumed_terminal_controlled_child_set_for_consumed_parent_join(
            store,
            parent_events,
            controlled_children,
            consumption,
        )?
        .is_some_and(|consumed_children| {
            consumed_children
                .iter()
                .any(|child| child.task_id == inspected_child_task_id)
        }),
    )
}

fn consumed_terminal_controlled_child_set_for_consumed_parent_join(
    store: &BrownieStore,
    parent_events: &[LedgerEvent],
    controlled_children: &[TaskRecord],
    consumption: &ConsumedParentJoinFingerprint,
) -> Result<Option<Vec<TaskRecord>>, String> {
    let mut consumed_children = controlled_children
        .iter()
        .filter(|child| is_parent_join_terminal_child_status(&child.status))
        .filter(|child| match child.recovery_cycle_provenance.as_ref() {
            Some(provenance) => {
                recovery_cycle_child_provenance_is_internally_valid(provenance)
                    && provenance.parent_join_child_completion_child_count
                        < consumption.child_completion_child_count
                    && parent_events.iter().any(|event| {
                        recovery_cycle_provenance_matches_parent_join(event, provenance)
                    })
            }
            None => true,
        })
        .cloned()
        .collect::<Vec<_>>();
    sort_controlled_child_records(&mut consumed_children);
    if consumed_children.len() != consumption.child_completion_child_count {
        return Ok(None);
    }
    if consumed_children
        .iter()
        .filter(|child| child.status == TaskStatus::Completed)
        .count()
        != consumption.child_terminal_completed_count
        || consumed_children
            .iter()
            .filter(|child| child.status == TaskStatus::Failed)
            .count()
            != consumption.child_terminal_failed_count
    {
        return Ok(None);
    }
    for child in &consumed_children {
        if !child_has_terminal_parent_join_outcome(store, child)
            .map_err(task_run_admission_rejection_message)?
        {
            return Ok(None);
        }
    }
    let child_evidence = consumed_children
        .iter()
        .map(|child| {
            parent_join_child_completion_evidence(store, child)
                .map_err(task_run_admission_rejection_message)
        })
        .collect::<Result<Vec<_>, _>>()?;
    let (child_completion_fingerprint, _) =
        parent_join_child_completion_fingerprint(&child_evidence);
    if child_completion_fingerprint != consumption.child_completion_fingerprint {
        return Ok(None);
    }
    Ok(Some(consumed_children))
}

fn continuation_controlled_children_for_consumed_parent_join(
    parent_events: &[LedgerEvent],
    controlled_children: &[TaskRecord],
    consumption: &ConsumedParentJoinFingerprint,
) -> Vec<TaskRecord> {
    let continuation_handoff_fingerprints =
        consumed_parent_join_continuation_handoff_fingerprints(parent_events, consumption);
    let mut continuation_children = controlled_children
        .iter()
        .filter(|child| {
            child_recovery_provenance_matches_consumed_parent_join(child, consumption)
                || child
                    .source_handoff_envelope_fingerprint
                    .as_ref()
                    .is_some_and(|fingerprint| {
                        continuation_handoff_fingerprints.contains(fingerprint)
                    })
        })
        .cloned()
        .collect::<Vec<_>>();
    sort_controlled_child_records(&mut continuation_children);
    continuation_children
}

fn consumed_parent_join_continuation_handoff_fingerprints(
    parent_events: &[LedgerEvent],
    consumption: &ConsumedParentJoinFingerprint,
) -> Vec<String> {
    let mut fingerprints = parent_events
        .iter()
        .filter(|event| event.kind == LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded)
        .filter_map(|event| event.payload.as_ref())
        .filter(|payload| {
            payload
                .get("continuation_materialization")
                .and_then(Value::as_bool)
                == Some(true)
                && payload
                    .get("handoff_envelope_status")
                    .and_then(Value::as_str)
                    == Some("Accepted")
                && payload
                    .get("parent_join_admission_id")
                    .and_then(Value::as_str)
                    == Some(consumption.admission_id.as_str())
                && payload
                    .get("parent_join_child_completion_fingerprint")
                    .and_then(Value::as_str)
                    == Some(consumption.child_completion_fingerprint.as_str())
                && payload_usize_eq(
                    payload,
                    "parent_join_child_completion_child_count",
                    consumption.child_completion_child_count,
                )
                && payload_usize_eq(
                    payload,
                    "parent_join_terminal_completed_child_count",
                    consumption.child_terminal_completed_count,
                )
                && payload_usize_eq(
                    payload,
                    "parent_join_terminal_failed_child_count",
                    consumption.child_terminal_failed_count,
                )
        })
        .filter_map(|payload| {
            payload
                .get("handoff_envelope_fingerprint")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|fingerprint| is_sha256_fingerprint(fingerprint))
                .map(ToString::to_string)
        })
        .collect::<Vec<_>>();
    fingerprints.sort();
    fingerprints.dedup();
    fingerprints
}

fn task_has_complete_controlled_child_provenance(record: &TaskRecord) -> bool {
    non_empty_record_string(record.parent_task_id.as_deref()).is_some()
        && non_empty_record_string(record.parent_run_id.as_deref()).is_some()
        && non_empty_record_string(record.source_candidate_id.as_deref()).is_some()
        && non_empty_record_string(record.source_handoff_envelope_id.as_deref()).is_some()
        && non_empty_record_string(record.source_handoff_envelope_fingerprint.as_deref()).is_some()
}

fn is_parent_join_terminal_child_status(status: &TaskStatus) -> bool {
    matches!(status, TaskStatus::Completed | TaskStatus::Failed)
}

fn is_parent_join_runnable_pending_child_status(status: &TaskStatus) -> bool {
    matches!(status, TaskStatus::Created | TaskStatus::Queued)
}

fn is_parent_join_non_runnable_child_status(status: &TaskStatus) -> bool {
    !is_parent_join_terminal_child_status(status)
        && !is_parent_join_runnable_pending_child_status(status)
}

fn sort_controlled_child_records(records: &mut [TaskRecord]) {
    records.sort_by(|left, right| {
        left.source_candidate_id
            .cmp(&right.source_candidate_id)
            .then(left.task_id.cmp(&right.task_id))
    });
}

fn controlled_child_records_for_parent_run(
    store: &BrownieStore,
    parent_task_id: Option<&str>,
    parent_run_id: &str,
    handoff_fingerprints: Option<&[String]>,
) -> Result<Vec<TaskRecord>, String> {
    let mut records = store
        .tasks()
        .list_tasks()
        .map_err(|error| error.to_string())?
        .into_iter()
        .filter(|record| record.parent_run_id.as_deref() == Some(parent_run_id))
        .filter(|record| match parent_task_id {
            Some(parent_task_id) => record.parent_task_id.as_deref() == Some(parent_task_id),
            None => true,
        })
        .filter(task_has_complete_controlled_child_provenance)
        .filter(|record| {
            let Some(fingerprints) = handoff_fingerprints else {
                return true;
            };
            record
                .source_handoff_envelope_fingerprint
                .as_ref()
                .is_some_and(|fingerprint| fingerprints.contains(fingerprint))
        })
        .collect::<Vec<_>>();
    sort_controlled_child_records(&mut records);
    Ok(records)
}

fn controlled_child_set_has_terminal_and_pending(
    store: &BrownieStore,
    parent_task_id: Option<&str>,
    parent_run_id: &str,
    handoff_fingerprints: Option<&[String]>,
) -> Result<bool, String> {
    let controlled_children = controlled_child_records_for_parent_run(
        store,
        parent_task_id,
        parent_run_id,
        handoff_fingerprints,
    )?;
    let has_terminal = controlled_children
        .iter()
        .any(|child| is_parent_join_terminal_child_status(&child.status));
    let has_pending = controlled_children
        .iter()
        .any(|child| !is_parent_join_terminal_child_status(&child.status));
    Ok(has_terminal && has_pending)
}

fn non_empty_record_string(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
}

fn controlled_child_failed_agent_loop_summary() -> TaskRunAgentLoopSummary {
    TaskRunAgentLoopSummary {
        final_state: "Failed".to_string(),
        completion_summary:
            "Controlled child task failed before agent loop completion; run parent task explicitly."
                .to_string(),
    }
}

fn recovery_cycle_budget_outcome_from_events(
    events: &[LedgerEvent],
) -> Option<RecoveryCycleBudgetOutcome> {
    events.iter().rev().find_map(|event| {
        if event.kind != LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded {
            return None;
        }
        let payload = event.payload.as_ref()?;
        if payload
            .get("recovery_cycle_budget_status")
            .and_then(Value::as_str)
            != Some("Exceeded")
        {
            return None;
        }

        let parent_join_admission_id =
            non_empty_payload_string(payload, "parent_join_admission_id")?;
        let parent_join_recovery_cycle_depth =
            payload_usize(payload, "parent_join_recovery_cycle_depth")?;
        let max_recovery_cycle_depth = payload_usize(payload, "max_recovery_cycle_depth")?;
        let blocked_candidate_count = payload_usize(payload, "blocked_candidate_count")
            .unwrap_or_else(|| payload_string_array(payload, "blocked_candidate_ids").len());
        if parent_join_recovery_cycle_depth <= max_recovery_cycle_depth
            || blocked_candidate_count == 0
        {
            return None;
        }
        let next_action = non_empty_payload_string(payload, "next_action")
            .unwrap_or_else(|| "stop_recovery_cycle_materialization".to_string());

        Some(RecoveryCycleBudgetOutcome {
            recovery_cycle_budget_status: "Exceeded".to_string(),
            parent_join_admission_id,
            parent_join_recovery_cycle_depth,
            max_recovery_cycle_depth,
            blocked_candidate_count,
            child_materialization_enabled: false,
            child_running_enabled: false,
            next_action,
        })
    })
}

fn non_empty_payload_string(payload: &Value, key: &str) -> Option<String> {
    payload
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
}

fn payload_usize(payload: &Value, key: &str) -> Option<usize> {
    payload
        .get(key)
        .and_then(Value::as_u64)
        .and_then(|value| usize::try_from(value).ok())
}

fn child_task_ids_for_parent_run(
    store: &BrownieStore,
    parent_run_id: &str,
) -> Result<Vec<String>, String> {
    let mut child_task_ids = store
        .tasks()
        .list_tasks()
        .map_err(|error| error.to_string())?
        .into_iter()
        .filter(|record| record.parent_run_id.as_deref() == Some(parent_run_id))
        .map(|record| record.task_id)
        .collect::<Vec<_>>();
    child_task_ids.sort();
    Ok(child_task_ids)
}

fn child_orchestration_outcome_for_materialized_children(
    store: &BrownieStore,
    parent_run_id: &str,
    child_task_ids_before_materialization: &[String],
) -> Result<Option<TaskRunChildOrchestrationOutcome>, String> {
    let mut materialized_children = store
        .tasks()
        .list_tasks()
        .map_err(|error| error.to_string())?
        .into_iter()
        .filter(|record| record.parent_run_id.as_deref() == Some(parent_run_id))
        .filter(|record| !child_task_ids_before_materialization.contains(&record.task_id))
        .filter(|record| {
            record.source_candidate_id.is_some()
                && record.source_handoff_envelope_id.is_some()
                && record.source_handoff_envelope_fingerprint.is_some()
        })
        .collect::<Vec<_>>();
    materialized_children.sort_by(|left, right| left.task_id.cmp(&right.task_id));
    if materialized_children.is_empty() {
        return Ok(None);
    }

    let materialized_child_task_ids = materialized_children
        .iter()
        .map(|record| record.task_id.clone())
        .collect::<Vec<_>>();
    let queued_child_task_ids = materialized_children
        .iter()
        .filter(|record| record.status == TaskStatus::Queued)
        .map(|record| record.task_id.clone())
        .collect::<Vec<_>>();
    if queued_child_task_ids.is_empty() {
        return Ok(None);
    }

    Ok(Some(TaskRunChildOrchestrationOutcome {
        parent_run_id: parent_run_id.to_string(),
        materialized_child_count: materialized_child_task_ids.len(),
        queued_child_count: queued_child_task_ids.len(),
        materialized_child_task_ids,
        queued_child_task_ids,
        child_running_enabled: false,
        next_action: "run_child_task_explicitly".to_string(),
    }))
}

fn child_orchestration_outcome_for_existing_queued_children(
    store: &BrownieStore,
    parent_run_id: &str,
) -> Result<Option<TaskRunChildOrchestrationOutcome>, String> {
    child_orchestration_outcome_for_existing_queued_children_from_handoff_fingerprints(
        store,
        parent_run_id,
        None,
    )
}

fn child_orchestration_outcome_for_latest_parent_join_queued_children(
    store: &BrownieStore,
    parent_task_id: &str,
    parent_run_id: &str,
    events: &[LedgerEvent],
) -> Result<Option<TaskRunChildOrchestrationOutcome>, String> {
    let Some(parent_join_admission_id) = events.iter().rev().find_map(|event| {
        if event.kind != LedgerEventKind::ParentJoinContinuationFingerprintConsumed {
            return None;
        }
        event
            .payload
            .as_ref()
            .and_then(|payload| non_empty_payload_string(payload, "admission_id"))
    }) else {
        return Ok(None);
    };
    let handoff_fingerprints = events
        .iter()
        .filter(|event| event.kind == LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded)
        .filter_map(|event| event.payload.as_ref())
        .filter(|payload| {
            payload
                .get("parent_join_admission_id")
                .and_then(Value::as_str)
                == Some(parent_join_admission_id.as_str())
        })
        .filter(|payload| {
            payload
                .get("continuation_materialization")
                .and_then(Value::as_bool)
                == Some(true)
        })
        .filter(|payload| {
            payload
                .get("handoff_envelope_status")
                .and_then(Value::as_str)
                == Some("Accepted")
        })
        .filter_map(|payload| non_empty_payload_string(payload, "handoff_envelope_fingerprint"))
        .collect::<Vec<_>>();
    if handoff_fingerprints.is_empty() {
        return Ok(None);
    }
    if controlled_child_set_has_terminal_and_pending(
        store,
        Some(parent_task_id),
        parent_run_id,
        Some(&handoff_fingerprints),
    )? {
        return Ok(None);
    }

    child_orchestration_outcome_for_existing_queued_children_from_handoff_fingerprints(
        store,
        parent_run_id,
        Some(&handoff_fingerprints),
    )
}

fn child_orchestration_outcome_for_existing_queued_children_from_handoff_fingerprints(
    store: &BrownieStore,
    parent_run_id: &str,
    handoff_fingerprints: Option<&[String]>,
) -> Result<Option<TaskRunChildOrchestrationOutcome>, String> {
    let mut queued_children = store
        .tasks()
        .list_tasks()
        .map_err(|error| error.to_string())?
        .into_iter()
        .filter(|record| record.parent_run_id.as_deref() == Some(parent_run_id))
        .filter(|record| record.status == TaskStatus::Queued)
        .filter(|record| {
            record.source_candidate_id.is_some()
                && record.source_handoff_envelope_id.is_some()
                && record.source_handoff_envelope_fingerprint.is_some()
        })
        .filter(|record| {
            let Some(fingerprints) = handoff_fingerprints else {
                return true;
            };
            record
                .source_handoff_envelope_fingerprint
                .as_ref()
                .is_some_and(|fingerprint| fingerprints.contains(fingerprint))
        })
        .collect::<Vec<_>>();
    queued_children.sort_by(|left, right| left.task_id.cmp(&right.task_id));
    if queued_children.is_empty() {
        return Ok(None);
    }

    let queued_child_task_ids = queued_children
        .iter()
        .map(|record| record.task_id.clone())
        .collect::<Vec<_>>();

    Ok(Some(TaskRunChildOrchestrationOutcome {
        parent_run_id: parent_run_id.to_string(),
        materialized_child_count: queued_child_task_ids.len(),
        queued_child_count: queued_child_task_ids.len(),
        materialized_child_task_ids: queued_child_task_ids.clone(),
        queued_child_task_ids,
        child_running_enabled: false,
        next_action: "run_child_task_explicitly".to_string(),
    }))
}

fn child_task_inspect_summary(
    store: &BrownieStore,
    task: &TaskRecord,
) -> Result<ChildTaskInspectSummary, String> {
    let events = store
        .tasks()
        .read_ledger_events(&task.run_id)
        .map_err(|error| format!("invalid params: {error}"))?;
    let completion_event = events
        .iter()
        .rev()
        .find(|event| event.kind == LedgerEventKind::AgentLoopCompleted);
    let (completion_final_state, completion_summary_preview) = completion_event
        .and_then(|event| event.payload.as_ref())
        .map(|payload| {
            (
                payload
                    .get("final_state")
                    .and_then(Value::as_str)
                    .map(ToString::to_string),
                payload
                    .get("completion_summary")
                    .and_then(Value::as_str)
                    .map(|summary| {
                        preview_with_limit(summary, CHILD_COMPLETION_SUMMARY_PREVIEW_CHARS)
                    }),
            )
        })
        .unwrap_or((None, None));
    let completion_result_fingerprint =
        child_completion_result_fingerprint(&events, completion_event);
    let final_response_preview =
        latest_content_preview(&events, LedgerEventKind::SecondPassLlmResponseReceived)
            .or_else(|| latest_content_preview(&events, LedgerEventKind::LlmResponseReceived));

    Ok(ChildTaskInspectSummary {
        task_id: task.task_id.clone(),
        run_id: task.run_id.clone(),
        status: task.status.clone(),
        parent_task_id: task.parent_task_id.clone(),
        parent_run_id: task.parent_run_id.clone(),
        source_candidate_id: task.source_candidate_id.clone(),
        source_handoff_envelope_id: task.source_handoff_envelope_id.clone(),
        source_handoff_envelope_fingerprint: task.source_handoff_envelope_fingerprint.clone(),
        source_intent_summary: task.source_intent_summary.clone(),
        recovery_cycle_provenance: task.recovery_cycle_provenance.clone(),
        verification_recovery_provenance: task.verification_recovery_provenance.clone(),
        verification_recovery_retry_provenance: task.verification_recovery_retry_provenance.clone(),
        event_count: events.len(),
        has_agent_loop_completed: completion_event.is_some(),
        completion_final_state,
        completion_result_fingerprint,
        completion_summary_preview,
        final_response_preview,
    })
}

fn child_completion_result_fingerprint(
    events: &[LedgerEvent],
    completion_event: Option<&LedgerEvent>,
) -> Option<String> {
    let payload = completion_event?.payload.as_ref()?;
    if let Some(fingerprint) = payload
        .get("completion_result_fingerprint")
        .and_then(Value::as_str)
        .filter(|fingerprint| fingerprint.starts_with("sha256:"))
    {
        return Some(fingerprint.to_string());
    }

    let final_state = payload.get("final_state").and_then(Value::as_str)?;
    let completion_summary = payload
        .get("completion_summary")
        .and_then(Value::as_str)
        .unwrap_or("");
    let final_response_preview =
        latest_content_preview(events, LedgerEventKind::SecondPassLlmResponseReceived)
            .or_else(|| latest_content_preview(events, LedgerEventKind::LlmResponseReceived))
            .unwrap_or_default();
    let canonical = json!({
        "version": "completion_result_fingerprint_legacy_v1",
        "final_state": final_state,
        "completion_summary_chars": completion_summary.chars().count(),
        "completion_summary_sha256": format!("sha256:{}", hex_sha256(completion_summary.as_bytes())),
        "final_response_preview_chars": final_response_preview.chars().count(),
        "final_response_preview_sha256": format!("sha256:{}", hex_sha256(final_response_preview.as_bytes())),
    });
    Some(format!(
        "sha256:{}",
        hex_sha256(canonical.to_string().as_bytes())
    ))
}

fn latest_content_preview(events: &[LedgerEvent], kind: LedgerEventKind) -> Option<String> {
    events
        .iter()
        .rev()
        .find(|event| event.kind == kind)
        .and_then(|event| {
            event
                .payload
                .as_ref()
                .and_then(|payload| payload.get("content_preview"))
                .and_then(Value::as_str)
                .map(ToString::to_string)
        })
}

fn ledger_event_summary(event: LedgerEvent) -> LedgerEventSummary {
    let kind = format!("{:?}", event.kind);
    LedgerEventSummary {
        event_id: event.event_id,
        task_id: event.task_id,
        run_id: event.run_id,
        kind,
        timestamp: event.timestamp,
        payload: sanitize_ledger_payload(event.payload),
    }
}

