fn timeline_entry(event: &LedgerEvent) -> String {
    let mut parts = vec![format!("{:?}", event.kind)];
    if let Some(Value::Object(payload)) = sanitize_ledger_payload(event.payload.clone()) {
        for key in [
            "tool_id",
            "status",
            "check_id",
            "verification_status",
            "verification_completion_gate_status",
            "required_verifier_count",
            "passed_verifier_count",
            "failed_verifier_count",
            "timed_out",
            "subtask_id",
            "parent_task_id",
            "parent_run_id",
            "source_candidate_id",
            "source_handoff_envelope_id",
            "handoff_id",
            "readiness_id",
            "plan_id",
            "contract_id",
            "admission_id",
            "snapshot_id",
            "guard_id",
            "decision_id",
            "manifest_id",
            "handoff_envelope_id",
            "queue_position",
            "queued_count",
            "handoff_count",
            "readiness_count",
            "plan_count",
            "contract_count",
            "admission_count",
            "snapshot_count",
            "guard_count",
            "dispatch_candidate_count",
            "eligible_candidate_count",
            "blocked_candidate_count",
            "candidate_count",
            "decision_count",
            "manifest_count",
            "handoff_ticket_count",
            "snapshot_fingerprint_count",
            "execution_enabled",
            "scheduler_handoff_enabled",
            "dispatch_enabled",
            "next_action",
            "readiness_status",
            "dispatch_plan_status",
            "dispatch_contract_status",
            "eligibility_status",
            "admission_status",
            "execution_gate_status",
            "scheduler_handoff_status",
            "guard_status",
            "handoff_preflight_status",
            "snapshot_validity_status",
            "snapshot_fingerprint",
            "decision_status",
            "candidate_status",
            "manifest_status",
            "handoff_envelope_status",
            "handoff_ticket_status",
            "replay_guard_status",
            "parent_join_continuation_status",
            "dispatch_decision",
            "dispatch_denial_reason",
            "candidate_denial_reason",
            "replay_guard_reason",
            "child_completion_fingerprint",
            "child_completion_child_count",
            "candidate_manifest_fingerprint",
            "handoff_envelope_fingerprint",
            "source_handoff_envelope_fingerprint",
            "recovery_cycle_provenance",
            "verification_recovery_provenance",
            "source_task_id",
            "source_run_id",
            "failure_fingerprint",
            "recovery_running_enabled",
            "readiness_fingerprint",
            "fingerprint_input_count",
            "bytes_read",
            "truncated",
            "reason",
            "provider",
            "model",
            "message_count",
            "state",
            "final_state",
            "completion_summary",
            "proposal_id",
            "operation",
            "path",
            "content_chars",
        ] {
            if let Some(value) = payload.get(key) {
                let value = value
                    .as_str()
                    .map(ToString::to_string)
                    .unwrap_or_else(|| value.to_string());
                parts.push(format!("{key}={value}"));
            }
        }
    }
    parts.join(" ")
}

fn resolve_task_start_policy(
    mode_id: Option<&str>,
    store: &BrownieStore,
) -> Result<CompiledModePolicy, String> {
    match mode_id {
        Some(mode_id) if !mode_id.trim().is_empty() => {
            resolve_workspace_mode_policy(store, mode_id)?
                .ok_or_else(|| "invalid params: unknown mode_id".to_string())
        }
        _ => Ok(BuiltinModeRegistry::default_policy()),
    }
}

fn workspace_mode_policies(store: &BrownieStore) -> Result<Vec<CompiledModePolicy>, String> {
    let mut policies = BuiltinModeRegistry::list();
    let Some(snapshot) = load_workspace_modepack(store.workspace_root())
        .map_err(|error| format!("modepack load failed: {error}"))?
    else {
        return Ok(policies);
    };
    for policy in snapshot.modes {
        if policies
            .iter()
            .any(|existing| existing.mode_id == policy.mode_id)
        {
            return Err(format!(
                "modepack mode duplicates existing mode_id: {}",
                policy.mode_id
            ));
        }
        policies.push(policy);
    }
    Ok(policies)
}

fn resolve_workspace_mode_policy(
    store: &BrownieStore,
    mode_id: &str,
) -> Result<Option<CompiledModePolicy>, String> {
    Ok(workspace_mode_policies(store)?
        .into_iter()
        .find(|policy| policy.mode_id == mode_id))
}

fn agent_loop_state_name(state: AgentLoopState) -> &'static str {
    match state {
        AgentLoopState::Created => "Created",
        AgentLoopState::LoadingMode => "LoadingMode",
        AgentLoopState::BuildingContext => "BuildingContext",
        AgentLoopState::CallingLlm => "CallingLlm",
        AgentLoopState::ParsingResponse => "ParsingResponse",
        AgentLoopState::ExecutingTool => "ExecutingTool",
        AgentLoopState::ApplyingPatch => "ApplyingPatch",
        AgentLoopState::SpawningSubtask => "SpawningSubtask",
        AgentLoopState::Waiting => "Waiting",
        AgentLoopState::Verifying => "Verifying",
        AgentLoopState::Completed => "Completed",
        AgentLoopState::Failed => "Failed",
        AgentLoopState::Cancelled => "Cancelled",
    }
}

