    #[test]
    fn task_run_with_readme_records_second_pass_events() {
        let _guard = ENV_LOCK.lock().expect("env lock");
        let temp = tempfile::tempdir().expect("tempdir");
        std::fs::write(
            temp.path().join("README.md"),
            "# Brownie\n\nWorkspace read smoke content that must not appear in the second-pass response.",
        )
        .expect("write");
        std::env::set_var("BROWNIE_WORKSPACE_ROOT", temp.path());

        let start = parse_line(
            r#"{"jsonrpc":"2.0","id":1,"method":"task.start","params":{"goal":"Inspect README before final response","mode_id":"orchestrator"}}"#,
        );
        let start_result = start.result.expect("start result");
        let task_id = start_result["task_id"]
            .as_str()
            .expect("task id")
            .to_string();
        let run_id = start_result["run_id"].as_str().expect("run id").to_string();

        let run = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":2,"method":"task.run","params":{{"task_id":"{task_id}"}}}}"#
        ));
        let run_result = run.result.expect("run result");
        assert_eq!(run_result["status"], "Completed");
        assert!(run_result.get("verification_completion_gate").is_none());

        let ledger = std::fs::read_to_string(
            temp.path()
                .join(".brownie/runs")
                .join(&run_id)
                .join("ledger.jsonl"),
        )
        .expect("ledger");
        let events: Vec<brownie_store::LedgerEvent> = ledger
            .lines()
            .map(|line| serde_json::from_str(line).expect("event"))
            .collect();
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::ToolExecutionCompleted));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskOrchestrationQueued));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskHandoffPrepared));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskSchedulerReadinessRecorded));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskDispatchPlanPrepared));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskDispatchContractPrepared));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskDispatchAdmissionEvaluated));
        assert!(events.iter().any(|event| {
            event.kind == LedgerEventKind::SubtaskDispatchReadinessSnapshotRecorded
        }));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskDispatcherGuardVerdictRecorded));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SubtaskDispatchDecisionRecorded));
        assert!(events.iter().any(|event| {
            event.kind == LedgerEventKind::SubtaskDispatchCandidateManifestRecorded
        }));
        assert!(events.iter().any(|event| {
            event.kind == LedgerEventKind::SubtaskDispatchHandoffEnvelopeRecorded
        }));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SecondPassPromptBuilt));
        let second_prompt = events
            .iter()
            .find(|event| event.kind == LedgerEventKind::SecondPassPromptBuilt)
            .expect("second pass prompt");
        let second_prompt_payload = second_prompt.payload.as_ref().expect("prompt payload");
        assert!(
            second_prompt_payload["context_total_events"]
                .as_u64()
                .expect("context total")
                > 0
        );
        assert_eq!(
            second_prompt_payload["context_max_events"].as_u64(),
            Some(MAX_LEDGER_CONTEXT_EVENTS as u64)
        );
        assert!(
            second_prompt_payload["context_included_events"]
                .as_u64()
                .expect("context included")
                <= MAX_LEDGER_CONTEXT_EVENTS as u64
        );
        assert_eq!(
            second_prompt_payload["context_last_included_event"],
            "LlmResponseReceived"
        );
        let second_prompt_preview = second_prompt_payload["prompt_preview"]
            .as_str()
            .expect("prompt preview");
        assert!(second_prompt_preview.contains("Subtask Orchestration:"));
        assert!(second_prompt_preview.contains("execution_enabled=false"));
        assert!(second_prompt_preview.contains("Prepared queued_count=1"));
        assert!(second_prompt_preview.contains("await_future_runtime_scheduler"));
        assert!(second_prompt_preview.contains("Blocked handoff_count=1"));
        assert!(second_prompt_preview.contains("dispatch_enabled=false"));
        assert!(second_prompt_preview.contains("await_runtime_scheduler_dispatch"));
        assert!(second_prompt_preview.contains("Blocked readiness_count=1"));
        assert!(second_prompt_preview.contains("await_runtime_subtask_dispatcher"));
        assert!(second_prompt_preview.contains("Blocked plan_count=1"));
        assert!(second_prompt_preview.contains("eligibility_status=Blocked"));
        assert!(second_prompt_preview.contains("await_dispatch_contract_implementation"));
        assert!(second_prompt_preview.contains("Blocked contract_count=1"));
        assert!(second_prompt_preview.contains("execution_gate_status=Blocked"));
        assert!(second_prompt_preview.contains("await_dispatch_admission_preconditions"));
        assert!(second_prompt_preview.contains("Blocked admission_count=1"));
        assert!(events
            .iter()
            .any(|event| event.kind == LedgerEventKind::SecondPassLlmRequestCreated));
        let second_response = events
            .iter()
            .find(|event| event.kind == LedgerEventKind::SecondPassLlmResponseReceived)
            .expect("second pass response");
        let preview = second_response
            .payload
            .as_ref()
            .and_then(|payload| payload.get("content_preview"))
            .and_then(Value::as_str)
            .expect("preview");
        assert!(preview.contains("Fake LLM final response"));
        assert!(!preview.contains("Workspace read smoke content"));

        std::env::remove_var("BROWNIE_WORKSPACE_ROOT");
    }

    #[test]
    fn task_run_executes_controlled_verifier_and_records_bounded_metadata() {
        let _guard = ENV_LOCK.lock().expect("env lock");
        let temp = tempfile::tempdir().expect("tempdir");
        std::fs::create_dir(temp.path().join("src")).expect("mkdir");
        std::fs::write(temp.path().join("README.md"), "# Brownie\n").expect("readme");
        std::fs::write(
            temp.path().join("Cargo.toml"),
            "[package]\nname = \"task_fmt_pass\"\nversion = \"0.1.0\"\nedition = \"2021\"\n",
        )
        .expect("manifest");
        std::fs::write(temp.path().join("src/lib.rs"), "pub fn ok() {}\n").expect("src");
        std::env::set_var("BROWNIE_WORKSPACE_ROOT", temp.path());

        let start = parse_line(
            r#"{"jsonrpc":"2.0","id":1,"method":"task.start","params":{"goal":"Verify formatting","mode_id":"verifier"}}"#,
        );
        let start_result = start.result.expect("start result");
        let task_id = start_result["task_id"]
            .as_str()
            .expect("task id")
            .to_string();
        let run_id = start_result["run_id"].as_str().expect("run id").to_string();

        let run = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":2,"method":"task.run","params":{{"task_id":"{task_id}"}}}}"#
        ));
        let run_result = run.result.expect("run result");
        assert_eq!(run_result["status"], "Completed");
        assert_eq!(
            run_result["verification_completion_gate"]["status"],
            "Passed"
        );
        assert_eq!(
            run_result["verification_completion_gate"]["required_verifier_tool_ids"][0],
            "verification.cargo_fmt_check"
        );

        let ledger = std::fs::read_to_string(
            temp.path()
                .join(".brownie/runs")
                .join(&run_id)
                .join("ledger.jsonl"),
        )
        .expect("ledger");
        let events: Vec<brownie_store::LedgerEvent> = ledger
            .lines()
            .map(|line| serde_json::from_str(line).expect("event"))
            .collect();
        let verifier_event = events
            .iter()
            .find(|event| {
                event.kind == LedgerEventKind::ToolExecutionCompleted
                    && event
                        .payload
                        .as_ref()
                        .and_then(|payload| payload.get("tool_id"))
                        .and_then(Value::as_str)
                        == Some("verification.cargo_fmt_check")
            })
            .expect("verification completion event");
        let payload = verifier_event.payload.as_ref().expect("payload");
        assert_eq!(payload["verification_status"], "Passed");
        assert_eq!(payload["process_launched"], true);
        assert_eq!(payload["output_redacted"], true);
        assert!(payload.get("standard_output_bytes").is_some());
        assert!(payload.get("standard_error_bytes").is_some());
        assert!(!ledger.contains("pub fn ok"));
        assert!(!ledger.contains("stdout"));
        assert!(!ledger.contains("stderr"));
        assert!(!ledger.contains("command"));
        let task_completed = events
            .iter()
            .find(|event| event.kind == LedgerEventKind::TaskCompleted)
            .expect("task completed event");
        let completed_payload = task_completed.payload.as_ref().expect("completion payload");
        assert_eq!(
            completed_payload["verification_completion_gate_status"],
            "Passed"
        );

        let events_response = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":3,"method":"run.events","params":{{"run_id":"{run_id}"}}}}"#
        ));
        let sanitized = events_response.result.expect("events result").to_string();
        assert!(sanitized.contains("verification_completion_gate_status"));
        assert!(sanitized.contains("verification_status"));
        assert!(sanitized.contains("standard_output_bytes"));
        assert!(!sanitized.contains("pub fn ok"));
        assert!(!sanitized.contains("stdout"));
        assert!(!sanitized.contains("stderr"));

        std::env::remove_var("BROWNIE_WORKSPACE_ROOT");
    }

