    #[test]
    fn run_inspection_methods_return_sanitized_summaries() {
        let _guard = ENV_LOCK.lock().expect("env lock");
        let temp = tempfile::tempdir().expect("tempdir");
        std::fs::write(
            temp.path().join("README.md"),
            "# Brownie\n\nsecret full content",
        )
        .expect("write");
        std::env::set_var("BROWNIE_WORKSPACE_ROOT", temp.path());

        let start = parse_line(
            r#"{"jsonrpc":"2.0","id":1,"method":"task.start","params":{"goal":"Inspect README before final response","mode_id":"orchestrator"}}"#,
        );
        let start_result = start.result.expect("start result");
        let task_id = start_result["task_id"]
            .as_str()
            .expect("task id")
            .to_string();
        let run_id = start_result["run_id"].as_str().expect("run id").to_string();
        let run = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":2,"method":"task.run","params":{{"task_id":"{task_id}"}}}}"#
        ));
        assert!(run.error.is_none());

        let events = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":3,"method":"run.events","params":{{"run_id":"{run_id}"}}}}"#
        ));
        assert!(events.error.is_none());
        let events_result = events.result.expect("events result");
        assert_eq!(events_result["run_id"], run_id);
        let serialized = serde_json::to_string(&events_result).expect("serialize");
        assert!(serialized.contains("output_preview"));
        assert!(serialized.contains("bytes_read"));
        assert!(serialized.contains("truncated"));
        assert!(!serialized.contains("secret full content"));
        assert!(!serialized.contains("\"content\""));
        assert!(!serialized.contains("full_content"));
        assert!(!serialized.contains("file_content"));
        assert!(!serialized.contains("raw_output"));

        let inspect = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":4,"method":"run.inspect","params":{{"run_id":"{run_id}"}}}}"#
        ));
        let summary = inspect.result.expect("inspect result")["run"].clone();
        assert!(summary["event_count"].as_u64().expect("event_count") > 0);
        assert_eq!(summary["has_tool_execution_completed"], true);
        assert_eq!(summary["has_subtask_orchestration_queued"], true);
        assert_eq!(summary["subtask_queue_count"], 1);
        assert_eq!(summary["has_subtask_handoff_prepared"], true);
        assert_eq!(summary["subtask_handoff_count"], 1);
        assert_eq!(summary["has_subtask_scheduler_readiness"], true);
        assert_eq!(summary["subtask_scheduler_readiness_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_plan_prepared"], true);
        assert_eq!(summary["subtask_dispatch_plan_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_contract_prepared"], true);
        assert_eq!(summary["subtask_dispatch_contract_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_admission_evaluated"], true);
        assert_eq!(summary["subtask_dispatch_admission_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_readiness_snapshot"], true);
        assert_eq!(summary["subtask_dispatch_readiness_snapshot_count"], 1);
        assert_eq!(summary["has_subtask_dispatcher_guard_verdict"], true);
        assert_eq!(summary["subtask_dispatcher_guard_verdict_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_decision"], true);
        assert_eq!(summary["subtask_dispatch_decision_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_candidate_manifest"], true);
        assert_eq!(summary["subtask_dispatch_candidate_manifest_count"], 1);
        assert_eq!(summary["has_subtask_dispatch_handoff_envelope"], true);
        assert_eq!(summary["subtask_dispatch_handoff_envelope_count"], 1);
        assert_eq!(summary["child_task_count"], 1);
        assert_eq!(
            summary["child_task_ids"]
                .as_array()
                .expect("child task ids")
                .len(),
            1
        );
        let child_tasks = summary["child_tasks"].as_array().expect("child tasks");
        assert_eq!(child_tasks.len(), 1);
        assert_eq!(child_tasks[0]["status"], "Queued");
        assert_eq!(child_tasks[0]["event_count"], 1);
        assert_eq!(child_tasks[0]["has_agent_loop_completed"], false);
        assert_eq!(child_tasks[0]["completion_final_state"], Value::Null);
        assert_eq!(child_tasks[0]["completion_summary_preview"], Value::Null);
        assert_eq!(child_tasks[0]["final_response_preview"], Value::Null);
        assert_eq!(child_tasks[0]["parent_task_id"], task_id);
        assert_eq!(child_tasks[0]["parent_run_id"], run_id);
        assert!(child_tasks[0]["source_candidate_id"]
            .as_str()
            .expect("source candidate id")
            .starts_with("subtask_run_"));
        assert!(child_tasks[0]["source_handoff_envelope_fingerprint"]
            .as_str()
            .expect("source handoff envelope fingerprint")
            .starts_with("sha256:"));
        assert_eq!(summary["has_second_pass"], true);
        assert!(summary["final_response_preview"]
            .as_str()
            .expect("preview")
            .contains("Fake LLM final response"));

        let task_inspect = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":5,"method":"task.inspect","params":{{"task_id":"{task_id}"}}}}"#
        ));
        assert_eq!(
            task_inspect.result.expect("task inspect result")["task"]["task_id"],
            task_id
        );

        std::env::remove_var("BROWNIE_WORKSPACE_ROOT");
    }

