    fn start_parent_with_queued_child() -> (String, String, TaskRecord, usize) {
        let start = parse_line(
            r#"{"jsonrpc":"2.0","id":1,"method":"task.start","params":{"goal":"Run parent orchestrator","mode_id":"orchestrator"}}"#,
        );
        let start_result = start.result.expect("start result");
        let parent_task_id = start_result["task_id"]
            .as_str()
            .expect("parent task id")
            .to_string();
        let parent_run_id = start_result["run_id"]
            .as_str()
            .expect("parent run id")
            .to_string();

        let parent_run = parse_line(&format!(
            r#"{{"jsonrpc":"2.0","id":2,"method":"task.run","params":{{"task_id":"{parent_task_id}"}}}}"#
        ));
        assert!(parent_run.error.is_none());
        assert_eq!(
            parent_run.result.expect("parent run result")["status"],
            "Completed"
        );

        let store = BrownieStore::from_env_or_cwd().expect("store");
        let all_tasks = store.tasks().list_tasks().expect("list tasks");
        let child = all_tasks
            .into_iter()
            .find(|record| record.parent_run_id.as_deref() == Some(parent_run_id.as_str()))
            .expect("queued child task");
        assert_eq!(child.status, TaskStatus::Queued);
        let parent_event_count = store
            .tasks()
            .read_ledger_events(&parent_run_id)
            .expect("parent ledger")
            .len();

        (parent_task_id, parent_run_id, child, parent_event_count)
    }

    fn assert_parent_join_readiness_outcome(
        outcome: &Value,
        parent_task_id: &str,
        parent_run_id: &str,
        child: &TaskRecord,
        terminal_status: &str,
    ) {
        assert_parent_join_readiness_outcome_with_child_set(
            outcome,
            parent_task_id,
            parent_run_id,
            child,
            terminal_status,
            true,
            1,
            &[],
            "run_parent_task_explicitly",
        );
    }

    fn assert_parent_join_readiness_outcome_with_child_set(
        outcome: &Value,
        parent_task_id: &str,
        parent_run_id: &str,
        child: &TaskRecord,
        terminal_status: &str,
        parent_join_ready: bool,
        terminal_controlled_child_count: usize,
        pending_controlled_child_task_ids: &[String],
        next_action: &str,
    ) {
        assert_parent_join_readiness_outcome_with_child_set_and_non_runnable(
            outcome,
            parent_task_id,
            parent_run_id,
            child,
            terminal_status,
            parent_join_ready,
            terminal_controlled_child_count,
            pending_controlled_child_task_ids,
            &[],
            next_action,
        );
    }

    fn assert_parent_join_readiness_outcome_with_child_set_and_non_runnable(
        outcome: &Value,
        parent_task_id: &str,
        parent_run_id: &str,
        child: &TaskRecord,
        terminal_status: &str,
        parent_join_ready: bool,
        terminal_controlled_child_count: usize,
        pending_controlled_child_task_ids: &[String],
        non_runnable_controlled_child_task_ids: &[String],
        next_action: &str,
    ) {
        assert_eq!(outcome["parent_task_id"], parent_task_id);
        assert_eq!(outcome["parent_run_id"], parent_run_id);
        assert_eq!(outcome["child_task_id"], child.task_id);
        assert_eq!(outcome["child_run_id"], child.run_id);
        assert_eq!(outcome["child_terminal_status"], terminal_status);
        assert_eq!(
            outcome["terminal_controlled_child_count"],
            terminal_controlled_child_count
        );
        assert_eq!(
            outcome["pending_controlled_child_count"],
            pending_controlled_child_task_ids.len()
        );
        assert_eq!(
            payload_string_array(outcome, "pending_controlled_child_task_ids"),
            pending_controlled_child_task_ids.to_vec()
        );
        assert_eq!(
            outcome["non_runnable_controlled_child_count"],
            non_runnable_controlled_child_task_ids.len()
        );
        assert_eq!(
            payload_string_array(outcome, "non_runnable_controlled_child_task_ids"),
            non_runnable_controlled_child_task_ids.to_vec()
        );
        assert_eq!(outcome["parent_join_ready"], parent_join_ready);
        assert_eq!(outcome["parent_running_enabled"], false);
        assert_eq!(outcome["next_action"], next_action);

        let serialized = outcome.to_string();
        for raw_marker in [
            "Run parent orchestrator",
            "Orchestrator mode may coordinate subtasks.",
            "RAW_FAILED_CHILD_PROMPT_SHOULD_NOT_APPEAR",
            "RAW_FAILED_CHILD_FILE_CONTENT_SHOULD_NOT_APPEAR",
            "RAW_M5_23_FAILED_CHILD_PROMPT_SHOULD_NOT_APPEAR",
            "RAW_M5_23_FAILED_CHILD_OUTPUT_SHOULD_NOT_APPEAR",
            "RAW_M5_24_FAILED_CHILD_PROMPT_SHOULD_NOT_APPEAR",
            "RAW_M5_24_FAILED_CHILD_OUTPUT_SHOULD_NOT_APPEAR",
            "Run M5.34 pending sibling raw goal",
            "Create M5.34 pending sibling.",
            "Run M5.35 non-runnable sibling raw goal",
            "Create M5.35 non-runnable sibling.",
            "provider",
            "stdout",
            "stderr",
            "input",
            "raw_failure_payload",
        ] {
            assert!(!serialized.contains(raw_marker));
        }
    }

